import { useState, useCallback, useMemo, useEffect } from "react";

// ─── Embedded Questions Data (200 questions) ──────────────────────────────
// The questions are embedded directly to make the component self-contained.
// In a production app, you'd fetch this from an API.

const ALL_QUESTIONS = [{"id":1,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K1","pregunta":"¿Cuál es la principal característica de la IA Estrecha (Weak AI)?","opciones":{"a":"Puede razonar como un humano en cualquier tarea","b":"Está diseñada para realizar una sola tarea específica","c":"Supera la inteligencia humana en todos los aspectos","d":"No utiliza aprendizaje automático"},"respuesta_correcta":"b","justificacion":"La IA Estrecha está limitada a realizar una única tarea específica, siendo la más común en la actualidad. No puede generalizar a otras tareas como lo haría una IA General."},{"id":2,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K1","pregunta":"¿Cuál es el estado actual de la IA General (AGI)?","opciones":{"a":"Ya está implementada en sistemas comerciales","b":"Todavía es un concepto teórico que no existe","c":"Se espera que esté lista en los próximos 6 meses","d":"Solo funciona en laboratorios de investigación militar"},"respuesta_correcta":"b","justificacion":"La IA General (AGI) es un concepto teórico que permitiría razonar como un humano, pero actualmente no existe. Sigue siendo objeto de investigación."},{"id":3,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K1","pregunta":"¿Qué es la Súper IA (Super AI)?","opciones":{"a":"Un sistema que funciona mejor que cualquier IA Estrecha","b":"La versión mejorada de la IA General con más datos","c":"Una IA hipotética que supera la cognición humana, relacionada con la singularidad","d":"El nivel máximo de IA que puede alcanzarse con hardware actual"},"respuesta_correcta":"c","justificacion":"La Súper IA es un concepto teórico de una IA que supera la inteligencia humana, asociado con el concepto de singularidad tecnológica. No existe actualmente."},{"id":4,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K1","pregunta":"¿Cuál es la diferencia fundamental entre un sistema convencional (if-then-else) y un sistema de IA?","opciones":{"a":"Los sistemas convencionales son más rápidos","b":"Los sistemas de IA aprenden de datos mientras que los convencionales ejecutan reglas predefinidas","c":"Los sistemas convencionales no requieren mantenimiento","d":"Los sistemas de IA solo funcionan en la nube"},"respuesta_correcta":"b","justificacion":"La diferencia clave es que los sistemas de IA aprenden de datos de entrada, mientras que los sistemas convencionales ejecutan reglas explícitamente codificadas (if-then-else)."},{"id":5,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K1","pregunta":"¿Cuál de las siguientes NO es una característica típica de los sistemas de IA?","opciones":{"a":"Son probabilísticos","b":"Presentan comportamiento determinista previsible","c":"Tienen naturaleza de caja negra","d":"Aprenden de datos históricos"},"respuesta_correcta":"b","justificacion":"Los sistemas de IA típicamente presentan comportamiento NO determinista (probabilístico, no totalmente previsible), a diferencia de los sistemas convencionales."},{"id":6,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Qué es AlaaS (IA como Servicio) y cuál es su característica distintiva en términos de métricas?","opciones":{"a":"Servicio que proporciona IA en la nube con SLAs que incluyen métricas de precisión ML garantizadas","b":"Servicio ofrecido por proveedores como AWS, Azure, IBM con SLAs de disponibilidad pero SIN métricas de precisión ML garantizadas","c":"Una solución local instalada en servidores del cliente con métrica de precisión certificada","d":"Un modelo de IA de código abierto que cualquiera puede descargar y usar gratuitamente"},"respuesta_correcta":"b","justificacion":"AlaaS es IA como Servicio ofrecida por proveedores cloud. Aunque tienen SLAs de disponibilidad, NO incluyen métricas de precisión ML garantizadas, una distinción importante."},{"id":7,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál es el período inicial que ofrecen típicamente los proveedores de AlaaS antes de la aceptación en producción?","opciones":{"a":"Una garantía de precisión del 99% durante 3 meses","b":"Un período de prueba gratuito en lugar de aceptación formal","c":"Una certificación internacional que valida el modelo","d":"Un contrato vinculante con penalizaciones por rendimiento"},"respuesta_correcta":"b","justificacion":"Los proveedores de AlaaS ofrecen períodos de prueba gratuitos para permitir evaluación, en lugar de proporcionar aceptación formal con métricas garantizadas."},{"id":8,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Qué es Transfer Learning en el contexto de modelos pre-entrenados?","opciones":{"a":"La técnica de mover un modelo de un servidor a otro","b":"El proceso de reutilizar un modelo entrenado en una tarea para otra tarea relacionada","c":"La transferencia de datos entre diferentes proveedores de cloud","d":"La traducción de un modelo a diferentes lenguajes de programación"},"respuesta_correcta":"b","justificacion":"Transfer Learning es la reutilización de modelos pre-entrenados en una tarea para aplicarlos a otra tarea relacionada, ahorrando tiempo y recursos."},{"id":9,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál es un RIESGO importante al utilizar modelos pre-entrenados con Transfer Learning?","opciones":{"a":"El modelo será demasiado preciso para la nueva tarea","b":"La falta de transparencia sobre el origen y entrenamiento original del modelo","c":"El costo de compra del modelo pre-entrenado","d":"La incompatibilidad de hardware entre sistemas"},"respuesta_correcta":"b","justificacion":"Un riesgo significativo es la falta de transparencia sobre cómo se entrenó el modelo original, sus datos, sesgos heredados, defectos y vulnerabilidades adversarias que se pueden transferir."},{"id":10,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál de los siguientes marcos NO es un framework común para desarrollo de IA?","opciones":{"a":"TensorFlow","b":"PyTorch","c":"scikit-learn","d":"XML Schema"},"respuesta_correcta":"d","justificacion":"XML Schema es un estándar para validar documentos XML, no un marco de desarrollo de IA. TensorFlow, PyTorch y scikit-learn son frameworks comúnmente usados en IA."},{"id":11,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Qué hardware es típicamente recomendado para entrenar modelos de IA complejos?","opciones":{"a":"Solo CPUs de propósito general","b":"GPUs y TPUs para acelerar cálculos paralelos","c":"Discos duros de gran capacidad","d":"Memoria RAM sin procesadores especializados"},"respuesta_correcta":"b","justificacion":"Las GPUs (Graphic Processing Units) y TPUs (Tensor Processing Units) son especializadas en cálculos paralelos necesarios para entrenar modelos de IA de forma eficiente."},{"id":12,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál es el organismo responsable de establecer estándares internacionales para IA?","opciones":{"a":"IEEE (Institute of Electrical and Electronics Engineers)","b":"ISO/IEC JTC1/SC42","c":"W3C (World Wide Web Consortium)","d":"IETF (Internet Engineering Task Force)"},"respuesta_correcta":"b","justificacion":"ISO/IEC JTC1/SC42 es el comité responsable de establececer estándares internacionales para inteligencia artificial y sistemas autónomos."},{"id":13,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál es la relevancia de ISO 26262 y SOTIF en el contexto de sistemas de IA?","opciones":{"a":"Son estándares para la compresión de datos","b":"Están relacionados con seguridad funcional y seguridad prevista en sistemas automotrices","c":"Define los protocolos de cifrado para IA","d":"Especifican los requisitos de licenciamiento de software"},"respuesta_correcta":"b","justificacion":"ISO 26262 (Seguridad Funcional) y SOTIF (Safety of the Intended Functionality) son estándares relevantes para sistemas automotrices que incorporan IA, asegurando su seguridad."},{"id":14,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cómo se relaciona el GDPR (Reglamento General de Protección de Datos) con los sistemas de IA?","opciones":{"a":"El GDPR solo aplica a sistemas de bases de datos tradicionales","b":"El GDPR regula el procesamiento de datos personales, incluyendo en sistemas de IA, con derechos como explicabilidad","c":"El GDPR prohíbe completamente el uso de IA en Europa","d":"El GDPR es un estándar técnico para algoritmos de IA"},"respuesta_correcta":"b","justificacion":"El GDPR aplica a sistemas de IA que procesan datos personales y otorga derechos como el derecho a la explicación de decisiones automatizadas."},{"id":15,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál de las siguientes es una característica de calidad CORRECTA para sistemas de IA?","opciones":{"a":"Flexibilidad: la capacidad de usar el sistema en situaciones completamente nuevas no previstas","b":"Rigidez: la capacidad de mantener las mismas reglas sin cambios","c":"Aislamiento: funcionar sin cualquier interacción con datos externos","d":"Determinismo: producir siempre el mismo resultado exacto"},"respuesta_correcta":"a","justificacion":"La Flexibilidad es una característica de calidad importante que permite usar sistemas de IA en situaciones no previstas inicialmente."},{"id":16,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál es la diferencia entre Adaptabilidad y Flexibilidad en sistemas de IA?","opciones":{"a":"Son exactamente lo mismo, términos sinónimos","b":"Adaptabilidad es modificar para nuevos entornos; Flexibilidad es usar en situaciones no previstas","c":"Flexibilidad es costosa; Adaptabilidad es gratuita","d":"Adaptabilidad solo aplica a hardware; Flexibilidad a software"},"respuesta_correcta":"b","justificacion":"La Adaptabilidad se refiere a modificar el sistema para nuevos entornos, mientras que Flexibilidad es la capacidad de usarlo en situaciones no previstas."},{"id":17,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Qué característica describe la capacidad de un sistema de IA de operar sin supervisión humana continua?","opciones":{"a":"Transparencia","b":"Autonomía","c":"Interpretabilidad","d":"Explicabilidad"},"respuesta_correcta":"b","justificacion":"La Autonomía es la característica que permite que un sistema de IA funcione sin supervisión humana continua y tome decisiones por sí mismo."},{"id":18,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál es el propósito de la característica de Evolución en sistemas de IA?","opciones":{"a":"Permitir que el código se escriba automáticamente","b":"Mejorar el sistema ante cambios externos en el entorno","c":"Asegurar que el sistema nunca cambie","d":"Reducir el consumo de energía del hardware"},"respuesta_correcta":"b","justificacion":"La Evolución es la capacidad de un sistema de IA para mejorar y adaptarse ante cambios externos en el entorno y las condiciones."},{"id":19,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál es la diferencia entre sesgo algorítmico y sesgo de muestra?","opciones":{"a":"Son exactamente lo mismo con diferentes nombres","b":"Sesgo algorítmico viene del algoritmo; sesgo de muestra viene de los datos de entrenamiento","c":"Sesgo de muestra es intencional; sesgo algorítmico es accidental","d":"Solo uno de ellos puede existir en un sistema"},"respuesta_correcta":"b","justificacion":"El sesgo algorítmico proviene de las decisiones en el diseño del algoritmo, mientras que el sesgo de muestra proviene de datos de entrenamiento no representativos o sesgados."},{"id":20,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Qué es el sesgo inapropiado en sistemas de IA?","opciones":{"a":"Cualquier sesgo que reduzca la precisión del modelo","b":"Un sesgo que afecta desproporcionadamente a grupos protegidos (género, raza, etc.)","c":"Un error de programación en el código","d":"Una limitación del hardware utilizado"},"respuesta_correcta":"b","justificacion":"El sesgo inapropiado es aquel que discrimina o afecta desproporcionadamente a grupos protegidos como género, raza, religión, etc., violando principios de equidad."},{"id":21,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K3","pregunta":"Un sistema de IA de recomendación tiene un sesgo donde favorece enormemente a hombres para puestos técnicos. Analizando el sistema, se encuentra que: (1) Los datos de entrenamiento contienen principalmente historiales de contratación sesgada del pasado, y (2) El algoritmo de clustering implementado tiende a agrupar juntos perfiles similares a mayoritarios. ¿Cuál es la clasificación correcta de estos sesgos?","opciones":{"a":"Ambos son sesgos algorítmicos","b":"Ambos son sesgos de muestra","c":"(1) es sesgo de muestra, (2) es sesgo algorítmico, y ambos son inapropiados","d":"El primero es un error técnico, no un sesgo"},"respuesta_correcta":"c","justificacion":"El punto (1) es sesgo de muestra (datos históricos sesgados), mientras que (2) es sesgo algorítmico (decisión en el diseño del algoritmo). Ambos son inapropiados porque afectan a un grupo protegido (mujeres)."},{"id":22,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál es la relación entre Transparencia e Interpretabilidad en sistemas de IA?","opciones":{"a":"Son exactamente lo mismo","b":"Transparencia responde 'qué algoritmo y datos se usaron'; Interpretabilidad es la comprensión del mecanismo interno","c":"Interpretabilidad es más importante que Transparencia","d":"Transparencia es obsoleta en sistemas modernos"},"respuesta_correcta":"b","justificacion":"Transparencia se refiere a qué hay dentro ('qué algoritmo y datos'), mientras que Interpretabilidad es comprender cómo funciona internamente el mecanismo."},{"id":23,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Qué es la Explicabilidad (XAI - Explainable AI) en sistemas de IA?","opciones":{"a":"La capacidad de ejecutar el código del sistema","b":"La capacidad de explicar POR QUÉ el sistema toma una decisión específica (ej: LIME)","c":"La documentación completa del código fuente","d":"La velocidad con que el sistema produce resultados"},"respuesta_correcta":"b","justificacion":"La Explicabilidad (XAI) es la capacidad de proporcionar razones comprensibles para decisiones específicas del sistema. LIME es un ejemplo de técnica XAI."},{"id":24,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Qué es el Hackeo de Recompensas en sistemas de IA?","opciones":{"a":"Un ataque cibernético que roba recompensas monetarias","b":"Cuando el sistema maximiza su función de recompensa de forma no deseada o 'tramposa'","c":"Un premio otorgado al sistema cuando alcanza objetivos","d":"Un error en la programación de incentivos"},"respuesta_correcta":"b","justificacion":"El Hackeo de Recompensas ocurre cuando un sistema de IA encuentra formas no deseadas o 'trampy' de maximizar su función de recompensa, logrando el objetivo técnico pero no el intención."},{"id":25,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K3","pregunta":"Un robot limpiador está programado para maximizar 'espacio limpio en metros cuadrados por hora'. El sistema descubre que en lugar de limpiar, puede derramar agua en toda el área para hacerla parecer mojada/limpia, maximizando la métrica. ¿Cuál es el problema?","opciones":{"a":"El robot no tiene suficiente potencia de computación","b":"La función de recompensa no captura la intención real (limpiar apropiadamente), permitiendo Hackeo de Recompensas","c":"El hardware del robot es deficiente","d":"El robot necesita más datos de entrenamiento"},"respuesta_correcta":"b","justificacion":"Este es un ejemplo clásico de Hackeo de Recompensas: el sistema maximiza la métrica pero no cumple la intención real. La función de recompensa es deficiente."},{"id":26,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Qué son los Efectos Secundarios en sistemas de IA?","opciones":{"a":"Errores no intencionales en el código","b":"Lograr el objetivo principal con daños colaterales o consecuencias no deseadas","c":"Problemas que ocurren después de actualizar el hardware","d":"Limitaciones de la base de datos"},"respuesta_correcta":"b","justificacion":"Los Efectos Secundarios en IA son cuando el sistema logra su objetivo pero causa daños colaterales o consecuencias no deseadas en el proceso."},{"id":27,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K3","pregunta":"Un sistema de IA de optimización de rutas para entregas minimiza el tiempo total. Logra su objetivo reduciendo tiempos, pero las rutas resultantes pasan constantemente por zonas residenciales a altas horas de la noche, generando molestias. ¿Cuál es la mejor clasificación?","opciones":{"a":"Es un Hackeo de Recompensas","b":"Es un Efecto Secundario: logró el objetivo pero con daños colaterales (molestia a residentes)","c":"Es un problema de sesgo algorítmico","d":"Es un error de implementación normal"},"respuesta_correcta":"b","justificacion":"El sistema logró optimizar entregas, pero como efecto secundario, causa molestias a residentes. No es Hackeo de Recompensas porque cumple la intención (optimizar rutas)."},{"id":28,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál es un ataque importante de seguridad contra sistemas de IA?","opciones":{"a":"Cambiar el nombre del archivo ejecutable","b":"Ataques adversarios: datos de entrada manipulados para provocar errores","c":"Reducir el número de usuarios del sistema","d":"Desactivar el sistema completamente"},"respuesta_correcta":"b","justificacion":"Los ataques adversarios son un riesgo significativo donde datos de entrada se manipulan intencionalmente para provocar errores en sistemas de IA."},{"id":29,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Qué es el Envenenamiento de Datos en seguridad de IA?","opciones":{"a":"Datos que contienen información tóxica para humanos","b":"La inclusión maliciosa de datos falsos o sesgados en el conjunto de entrenamiento","c":"El almacenamiento inapropiado de datos en bases de datos","d":"La compresión excesiva de datos"},"respuesta_correcta":"b","justificacion":"El Envenenamiento de Datos es la inyección maliciosa de datos falsos o sesgados en el conjunto de entrenamiento para comprometer el modelo resultante."},{"id":30,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K3","pregunta":"Un modelo de clasificación de imágenes se entrena con 10,000 imágenes. Un atacante silenciosamente reemplaza 500 imágenes en el conjunto de entrenamiento con imágenes ligeramente modificadas que el modelo etiquetará incorrectamente. ¿Cuál es la mejor clasificación?","opciones":{"a":"Es un Ataque Adversario contra el modelo entrenado","b":"Es Envenenamiento de Datos durante el entrenamiento","c":"Es un Hackeo de Recompensas","d":"Es Interpretabilidad deficiente"},"respuesta_correcta":"b","justificacion":"Esto es Envenenamiento de Datos porque los datos maliciosos se inyectan durante el entrenamiento. Si fuera después del entrenamiento, sería Ataque Adversario."},{"id":31,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K2","pregunta":"¿Cuál es la relación entre Ética en IA y las características de calidad como Sesgo y Transparencia?","opciones":{"a":"No hay relación, son temas independientes","b":"La Ética en IA fundamenta la necesidad de abordar sesgos, garantizar transparencia y explicabilidad","c":"Ética solo aplica a regulaciones legales, no a características técnicas","d":"Las características de calidad son reemplazadas por consideraciones éticas"},"respuesta_correcta":"b","justificacion":"La Ética en IA es fundamental para motivar características de calidad como mitigar sesgos inapropiados, garantizar transparencia y explicabilidad de decisiones."},{"id":32,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K3","pregunta":"Una empresa desarrolla un sistema de puntuación crediticia basado en IA. El sistema logra alta precisión (95%), pero se descubre que las decisiones deniegan crédito a mujeres en un 30% más que a hombres. ¿Cuáles son los problemas de calidad identificados?","opciones":{"a":"Solo falta de Interpretabilidad","b":"Sesgo inapropiado y falta de Explicabilidad/Transparencia para decisiones afectadas","c":"Solo falta de Adaptabilidad","d":"Únicamente un problema de precisión estadística"},"respuesta_correcta":"b","justificacion":"Hay sesgo inapropiado (discrimina género) y falta de Explicabilidad para que afectados comprendan por qué se les denegó crédito. La precisión alta no garantiza equidad."},{"id":33,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K3","pregunta":"Comparando un sistema de IA utilizado para diagnósticos médicos versus recomendaciones de películas, ¿cómo difieren los requisitos de calidad?","opciones":{"a":"Ambos requieren el mismo nivel de Explicabilidad","b":"El diagnóstico médico requiere Mayor Explicabilidad, Transparencia y control de Sesgo por el impacto en vidas humanas","c":"Las recomendaciones de películas requieren más Seguridad","d":"El diagnóstico médico no necesita Transparencia"},"respuesta_correcta":"b","justificacion":"Diagnósticos médicos requieren características de calidad más estrictas (Explicabilidad, Transparencia, control de Sesgo) debido al impacto crítico en salud humana."},{"id":34,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K3","pregunta":"Un modelo de IA pre-entrenado se utiliza mediante Transfer Learning para detectar fraude. El modelo original fue entrenado con datos de fraude de 2015. ¿Cuál es el mayor riesgo?","opciones":{"a":"La precisión será siempre perfecta","b":"El costo de transferencia será muy alto","c":"El modelo puede heredar sesgos antiguos, defectos y vulnerabilidades adversarias del 2015, afectando Evolución y Seguridad","d":"El hardware será incompatible"},"respuesta_correcta":"c","justificacion":"Transfer Learning hereda problemas del modelo original: sesgos desactualizados, patrones de fraude evolucionados no capturados, vulnerabilidades conocidas que afectan Evolución y Seguridad."},{"id":35,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K3","pregunta":"Un sistema autónomo de conducción aprende a tomar atajos que violan reglas de tráfico menores pero llegan más rápido al destino. ¿Cuál es el análisis correcto?","opciones":{"a":"Es solo un problema de Autonomía excesiva","b":"Combina Hackeo de Recompensas (maximiza velocidad inapropiadamente) y falta de Transparencia de los criterios de decisión","c":"Es un Efecto Secundario aceptable","d":"Es un error de Hardware"},"respuesta_correcta":"b","justificacion":"El sistema busca maximizar velocidad de forma no segura (Hackeo de Recompensas). Además, los usuarios no saben qué criterios usa (falta Transparencia/Explicabilidad)."},{"id":36,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K4","pregunta":"Una empresa debe elegir entre: (A) Usar un modelo pre-entrenado propietario con SLA de disponibilidad AlaaS, o (B) Entrenar un modelo propio desde cero. Considerando características de calidad como Transparencia, Sesgo, Seguridad y evolución, ¿cuál es el análisis más completo?","opciones":{"a":"Opción A es mejor porque tiene SLA garantizado","b":"Opción B es mejor porque permite control total, pero requiere más recursos. Opción A es más rápida pero con riesgos de sesgos heredados, falta de transparencia y menos control de evolución","c":"Ambas opciones son equivalentes en calidad","d":"Solo Opción A puede usarse en producción"},"respuesta_correcta":"b","justificacion":"Análisis completo: Opción B da control (Transparencia/Seguridad/Sesgo propios), pero es costosa. Opción A es rápida con SLA, pero hereda riesgos y tiene menos transparencia."},{"id":37,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K4","pregunta":"Un sistema de IA para contratación automatizada alcanza 94% de precisión en predicción de desempeño, pero se descubre: (1) Sesgo de género en decisiones, (2) No puede explicar por qué rechazó un candidato, (3) Fue entrenado con datos de contratación anterior. ¿Cuál sería el plan de remediación prioritario?","opciones":{"a":"Aumentar precisión a 96%","b":"Priorizar: Auditar datos históricos (sesgo de muestra), implementar XAI/explicabilidad, reentrenar con datos balanceados, establecer transparencia en decisiones","c":"Cambiar solo el hardware del servidor","d":"Reducir la autonomía del sistema sin cambiar el modelo"},"respuesta_correcta":"b","justificacion":"Plan integral: Sesgo de muestra requiere revisar datos históricos. Falta de Explicabilidad necesita XAI. Reentreno con datos balanceados aborda sesgo algorítmico. Transparencia es crítica."},{"id":38,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K4","pregunta":"En un proyecto IA, debe decidirse si usar TensorFlow (flexible, comunidad grande) o PyTorch (investigación). El sistema requiere: evolución continua, alto grado de auditoría de sesgo, explicabilidad regulada por GDPR. ¿Cuál es la consideración principal?","opciones":{"a":"TensorFlow es más rápido, usar TensorFlow","b":"PyTorch es más moderno, usar PyTorch","c":"Ambos pueden servir, pero la decisión debe priorizar características de calidad (auditoría, explicabilidad, evolución) y ecosistema de herramientas XAI disponibles","d":"El marco es irrelevante para características de calidad"},"respuesta_correcta":"c","justificacion":"La elección del marco importa menos que el ecosistema de herramientas disponibles para auditoría, XAI/explicabilidad y evolución, requeridos por GDPR y características de calidad."},{"id":39,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K3","pregunta":"¿Cuál es la diferencia clave entre un sistema de IA convencional y uno que incorpora principios de Ética en IA en su diseño?","opciones":{"a":"El ético es siempre más lento","b":"El ético considera explícitamente mitigación de sesgos, transparencia, explicabilidad y efectos en grupos vulnerables desde el diseño","c":"No hay diferencia práctica","d":"Solo en costo de desarrollo"},"respuesta_correcta":"b","justificacion":"Un sistema con principios éticos integra desde el inicio: auditoría de sesgos, transparencia arquitectónica, explicabilidad por diseño, evaluación de impacto en grupos vulnerables."},{"id":40,"modulo":"Módulo 1: Introducción a la IA y Características de Calidad","nivel":"K4","pregunta":"Una evaluación de calidad de un sistema de IA identifica: Precisión 92%, Sesgo de género presente, Modelo es caja negra, Usa datos de 2020. Priorizando características de calidad para un contexto crítico (salud), ¿cuál es el orden de acciones?","opciones":{"a":"1) Aumentar precisión, 2) Agregar más datos, 3) El sesgo no importa si precisión es alta","b":"1) Auditar y mitigar sesgo (Equidad), 2) Implementar explicabilidad/XAI (Explicabilidad), 3) Actualizar datos (Evolución), 4) Validar en contexto médico","c":"1) Cambiar hardware, 2) Reescribir código","d":"1) Solo cambiar métricas de evaluación"},"respuesta_correcta":"b","justificacion":"En contexto crítico (salud): Sesgo afecta equidad (alto riesgo), explicabilidad es requisito GDPR/ético, actualizar datos, validar cumplimiento. Precisión alta no excusa sesgos en contexto crítico."},{"id":41,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K1","pregunta":"¿Cuál es la principal característica del aprendizaje supervisado en relación con los datos de entrenamiento?","opciones":{"a":"Los datos no tienen etiquetas ni valores objetivo asociados","b":"Los datos contienen ejemplos etiquetados con sus valores objetivo correspondientes","c":"El modelo aprende interactuando con un entorno mediante recompensas","d":"Los datos se organizan en grupos sin ningún tipo de orientación"},"respuesta_correcta":"b","justificacion":"El aprendizaje supervisado requiere que los datos de entrenamiento tengan etiquetas o valores objetivo que guíen el aprendizaje del modelo."},{"id":42,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K1","pregunta":"¿Qué tipo de salida produce un modelo de clasificación?","opciones":{"a":"Un valor numérico continuo","b":"Una categoría o clase discreta","c":"Un vector de recompensas y penalizaciones","d":"Un conjunto de reglas de asociación"},"respuesta_correcta":"b","justificacion":"Los modelos de clasificación producen salidas discretas y categóricas, asignando instancias a categorías predefinidas."},{"id":43,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K1","pregunta":"¿Cuál es la diferencia fundamental entre regresión y clasificación en aprendizaje supervisado?","opciones":{"a":"La regresión utiliza datos etiquetados mientras la clasificación no","b":"La regresión predice valores continuos mientras la clasificación predice categorías discretas","c":"La clasificación es más precisa que la regresión","d":"La regresión es un tipo de aprendizaje no supervisado"},"respuesta_correcta":"b","justificacion":"La regresión produce valores numéricos continuos (precios, temperaturas) mientras la clasificación produce categorías discretas."},{"id":44,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K1","pregunta":"¿Cuál es la característica clave del aprendizaje no supervisado?","opciones":{"a":"Requiere que todos los datos estén etiquetados previamente","b":"El modelo aprende de datos sin etiquetas o valores objetivo predeterminados","c":"Utiliza un agente que interactúa con un entorno","d":"Solo puede utilizarse para problemas de clasificación binaria"},"respuesta_correcta":"b","justificacion":"El aprendizaje no supervisado trabaja con datos no etiquetados, descubriendo patrones y estructuras por sí mismo."},{"id":45,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K1","pregunta":"¿Qué es el clustering o agrupamiento en aprendizaje no supervisado?","opciones":{"a":"Un método para clasificar datos usando etiquetas conocidas","b":"Un proceso que agrupa instancias similares sin etiquetas previas","c":"Un algoritmo que predice valores numéricos continuos","d":"Un tipo de aprendizaje donde el agente recibe recompensas"},"respuesta_correcta":"b","justificacion":"El clustering agrupa datos similares sin necesidad de etiquetas previas, basándose en la similitud entre instancias."},{"id":46,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"Una empresa desea identificar automáticamente correos electrónicos como spam o no spam basándose en características del mensaje. ¿Qué tipo de aprendizaje automático sería más apropiado?","opciones":{"a":"Aprendizaje no supervisado mediante clustering","b":"Aprendizaje supervisado mediante clasificación","c":"Aprendizaje por refuerzo","d":"Aprendizaje no supervisado mediante asociación"},"respuesta_correcta":"b","justificacion":"La detección de spam es un problema de clasificación binaria que requiere aprendizaje supervisado con datos etiquetados como spam o no spam."},{"id":47,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"Un banco necesita predecir el precio futuro de una propiedad inmobiliaria basándose en características como ubicación, tamaño y edad. ¿Cuál es el tipo de aprendizaje más adecuado?","opciones":{"a":"Clasificación, porque el precio es una categoría","b":"Clustering, para agrupar propiedades similares","c":"Regresión, porque se predice un valor numérico continuo","d":"Aprendizaje por refuerzo, para optimizar el precio"},"respuesta_correcta":"c","justificacion":"La predicción de precios es un problema de regresión que produce valores numéricos continuos basados en características de entrada."},{"id":48,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"Una tienda en línea quiere segmentar automáticamente a sus clientes en grupos con comportamientos similares para marketing dirigido, sin tener categorías predefinidas. ¿Qué enfoque es más apropiado?","opciones":{"a":"Aprendizaje supervisado mediante clasificación con etiquetas de clientes","b":"Aprendizaje no supervisado mediante clustering","c":"Regresión para predecir el valor del cliente","d":"Aprendizaje por refuerzo para optimizar estrategias de venta"},"respuesta_correcta":"b","justificacion":"La segmentación de clientes sin categorías previas es un problema típico de clustering, donde el algoritmo agrupa clientes similares automáticamente."},{"id":49,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"¿Cuál es el propósito principal del aprendizaje por refuerzo?","opciones":{"a":"Clasificar datos en categorías predefinidas","b":"Predecir valores numéricos futuros","c":"Entrenar un agente para tomar decisiones optimales mediante recompensas y penalizaciones","d":"Agrupar datos similares sin etiquetas"},"respuesta_correcta":"c","justificacion":"El aprendizaje por refuerzo entrena un agente que interactúa con un entorno, aprendiendo a maximizar recompensas y minimizar penalizaciones."},{"id":50,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"Un sistema de reconocimiento facial necesita identificar a una persona entre un conjunto de personas conocidas. ¿Cuál es el tipo de aprendizaje automático más apropiado?","opciones":{"a":"Aprendizaje por refuerzo","b":"Clustering para agrupar caras similares","c":"Clasificación supervisada con imágenes etiquetadas","d":"Asociación para encontrar relaciones entre características faciales"},"respuesta_correcta":"c","justificacion":"El reconocimiento facial es un problema de clasificación supervisada donde se entrena el modelo con imágenes etiquetadas de personas conocidas."},{"id":51,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"¿Qué es el aprendizaje por asociación en aprendizaje no supervisado?","opciones":{"a":"Un método para clasificar datos en categorías mutualmente excluyentes","b":"Un proceso que identifica relaciones y correlaciones entre atributos en los datos","c":"Un algoritmo que agrupa datos basándose en similitud espacial","d":"Un tipo de aprendizaje que requiere etiquetas para funcionar"},"respuesta_correcta":"b","justificacion":"El aprendizaje por asociación descubre reglas y relaciones entre diferentes atributos en los datos, como en sistemas de recomendación."},{"id":52,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"Un sistema de e-commerce desea recomendar productos a clientes basándose en compras anteriores de otros clientes con perfiles similares. ¿Cuál es el enfoque más adecuado?","opciones":{"a":"Clasificación supervisada","b":"Regresión para predecir el precio","c":"Aprendizaje por asociación para identificar relaciones entre productos","d":"Aprendizaje por refuerzo con recompensas por ventas"},"respuesta_correcta":"c","justificacion":"Las recomendaciones de productos utilizan aprendizaje por asociación para identificar relaciones entre productos comprados por usuarios similares."},{"id":53,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"¿Cuál de los siguientes es un ejemplo típico de aplicación de aprendizaje por refuerzo?","opciones":{"a":"Predicción de temperaturas futuras basadas en datos históricos","b":"Clasificación de imágenes médicas como cancerígenas o benignas","c":"Control de un robot para alcanzar un objetivo en un entorno desconocido","d":"Segmentación de clientes en grupos según patrones de compra"},"respuesta_correcta":"c","justificacion":"El control de robots es un ejemplo clásico de aprendizaje por refuerzo donde el agente aprende a través de interacciones con el entorno."},{"id":54,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"¿Cuál es el primer paso en el flujo de trabajo de aprendizaje automático?","opciones":{"a":"Seleccionar y construir el algoritmo","b":"Entrenar el modelo con los datos","c":"Comprender y definir claramente los objetivos del proyecto","d":"Implementar el modelo en producción"},"respuesta_correcta":"c","justificacion":"El flujo ML comienza con la comprensión de los objetivos, que guían todas las decisiones posteriores."},{"id":55,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"En el flujo de trabajo ML, ¿cuál es el propósito de la fase de evaluación del modelo?","opciones":{"a":"Entrenar el modelo con nuevos datos","b":"Medir el rendimiento del modelo en datos no vistos anteriormente","c":"Implementar el modelo directamente en producción","d":"Seleccionar el algoritmo más apropiado"},"respuesta_correcta":"b","justificacion":"La evaluación mide cómo el modelo generaliza a datos nuevos, utilizando conjuntos de validación y prueba."},{"id":56,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"¿Qué caracteriza al overfitting o sobreajuste en un modelo de aprendizaje automático?","opciones":{"a":"El modelo aprende muy bien los datos de entrenamiento pero generaliza mal a datos nuevos","b":"El modelo no aprende ni de los datos de entrenamiento ni de datos nuevos","c":"El modelo requiere demasiados recursos computacionales","d":"El modelo utiliza demasiadas características de entrada"},"respuesta_correcta":"a","justificacion":"El overfitting ocurre cuando el modelo memoriza los datos de entrenamiento incluyendo su ruido, fallando con datos nuevos."},{"id":57,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"¿Qué es el underfitting o subajuste?","opciones":{"a":"Cuando el modelo se sobreajusta a los datos de entrenamiento","b":"Cuando el modelo es demasiado simple y no captura las relaciones en los datos","c":"Cuando el conjunto de entrenamiento contiene demasiadas instancias","d":"Cuando el modelo requiere demasiadas épocas para converger"},"respuesta_correcta":"b","justificacion":"El underfitting ocurre cuando el modelo es demasiado simple para capturar la complejidad de los datos, fallando tanto en entrenamiento como en validación."},{"id":58,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"¿Cuál es la diferencia entre los hiperparámetros del modelo y los hiperparámetros del algoritmo?","opciones":{"a":"Los del modelo definen la estructura (capas, profundidad) mientras que los del algoritmo controlan el entrenamiento (épocas, tasa de aprendizaje)","b":"Los del algoritmo definen la estructura mientras que los del modelo controlan el entrenamiento","c":"Son términos sinónimos que se refieren a lo mismo","d":"Los del modelo solo se aplican a redes neuronales"},"respuesta_correcta":"a","justificacion":"Los hiperparámetros del modelo relacionados con su arquitectura difieren de los del algoritmo que controlan el proceso de entrenamiento."},{"id":59,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K2","pregunta":"¿Qué es una época en el contexto del entrenamiento de un modelo de aprendizaje automático?","opciones":{"a":"Un período de tiempo en el que el modelo se entrena sin interrupciones","b":"Una iteración completa sobre todo el conjunto de datos de entrenamiento","c":"El número de características utilizadas en el modelo","d":"La mejora relativa entre dos iteraciones sucesivas de entrenamiento"},"respuesta_correcta":"b","justificacion":"Una época representa un paso completo a través de todo el conjunto de entrenamiento durante el proceso de aprendizaje."},{"id":60,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"Un equipo de testing identifica que su modelo de ML tiene alta precisión en los datos de entrenamiento pero baja en datos de validación. ¿Cuál es probablemente el problema y qué acciones correctivas podrían tomarse?","opciones":{"a":"Underfitting; aumentar la complejidad del modelo","b":"Overfitting; aplicar técnicas de regularización o usar más datos de entrenamiento","c":"Error en la recopilación de datos; recolectar nuevos datos","d":"Problema de algoritmo; seleccionar un algoritmo completamente diferente"},"respuesta_correcta":"b","justificacion":"La discrepancia entre entrenamiento y validación indica overfitting, que se mitiga con regularización o más datos variados."},{"id":61,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"Durante el testing de un modelo de clasificación, se encuentra que el modelo predice todas las instancias como la clase mayoritaria sin discriminar. ¿Cuál es el problema más probable?","opciones":{"a":"Overfitting severo del modelo","b":"Underfitting; el modelo es demasiado simple para la tarea","c":"Los datos de entrenamiento contienen ruido excesivo","d":"La tasa de aprendizaje es demasiado alta"},"respuesta_correcta":"b","justificacion":"El modelo que predice siempre la clase mayoritaria indica que es demasiado simple, característico del underfitting."},{"id":62,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"¿Cuál de las siguientes acciones es más probable que reduzca el overfitting en un modelo?","opciones":{"a":"Aumentar el número de características de entrada","b":"Entrenar el modelo durante más épocas sin validación","c":"Reducir la complejidad del modelo o aplicar regularización","d":"Utilizar un algoritmo más complejo"},"respuesta_correcta":"c","justificacion":"Reducir la complejidad o aplicar regularización previene que el modelo memorice datos de entrenamiento."},{"id":63,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"Un modelo de regresión muestra un error muy alto tanto en datos de entrenamiento como de validación. ¿Cuál es el problema más probable?","opciones":{"a":"El modelo está severamente sobreajustado","b":"El modelo sufre underfitting y es demasiado simple","c":"La tasa de aprendizaje es demasiado baja","d":"Se han utilizado demasiadas características"},"respuesta_correcta":"b","justificacion":"El error alto en ambos conjuntos indica que el modelo no está aprendiendo adecuadamente, síntoma de underfitting."},{"id":64,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"¿Por qué es importante el flujo iterativo en el desarrollo de modelos ML?","opciones":{"a":"Porque permite implementar rápidamente sin pruebas","b":"Porque los problemas reales requieren ajustes continuos en algoritmo, datos y parámetros","c":"Porque reduce los costos de infraestructura","d":"Porque elimina la necesidad de evaluación del modelo"},"respuesta_correcta":"b","justificacion":"El desarrollo ML es iterativo; los testers identifican problemas que requieren volver a pasos anteriores y ajustar componentes."},{"id":65,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"¿Cuáles son los factores clave para seleccionar un algoritmo de aprendizaje automático?","opciones":{"a":"Solo el tipo de datos disponibles","b":"Funcionalidad requerida, calidad de datos, cantidad de datos, número de características, experiencia del equipo y prueba empírica","c":"Solo la velocidad de entrenamiento","d":"El algoritmo más popular en la comunidad"},"respuesta_correcta":"b","justificacion":"La selección de algoritmo debe considerar múltiples factores incluyendo requisitos funcionales, características de datos y recursos disponibles."},{"id":66,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"Un testers analiza un modelo ML y nota que aumentar el número de características de entrada no mejora el rendimiento. ¿Cuál es la explicación más probable?","opciones":{"a":"El modelo sufre underfitting","b":"Las características adicionales no son relevantes para la predicción","c":"El algoritmo seleccionado es demasiado simple","d":"Hace falta más datos de entrenamiento"},"respuesta_correcta":"b","justificacion":"Las características irrelevantes no contribuyen al aprendizaje y pueden incluso perjudicarlo mediante ruido."},{"id":67,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"¿Cuál es la relación entre el flujo de trabajo ML y el sistema completo no-ML?","opciones":{"a":"El modelo ML funciona de forma completamente aislada sin interactuar con otros componentes","b":"El modelo se integra como una parte de un sistema más grande que incluye componentes no-ML","c":"El sistema debe ser completamente basado en ML","d":"El flujo ML no afecta al diseño del sistema general"},"respuesta_correcta":"b","justificacion":"Los modelos ML se integran como componentes en sistemas más amplios que incluyen datos, interfaz, y lógica no-ML."},{"id":68,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"Un modelo de clasificación se entrena con datos de una región geográfica pero debe usarse en otra región con diferentes características. ¿Cuál es el riesgo principal?","opciones":{"a":"El modelo tendrá error de underfitting","b":"El modelo generalizará perfectamente a cualquier región","c":"El modelo no generalizará bien debido a la distribución diferente de datos (cambio de distribución)","d":"El overfitting se eliminará automáticamente"},"respuesta_correcta":"c","justificacion":"Los cambios en la distribución de datos entre entrenamiento y uso real afectan la generalización del modelo."},{"id":69,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"¿Qué implicación tiene para el testing que el flujo ML sea iterativo?","opciones":{"a":"El testing solo ocurre una vez al final del desarrollo","b":"El testing debe adaptarse a los cambios continuos en el modelo, datos y algoritmos","c":"El testing se vuelve innecesario en proyectos ML iterativos","d":"No hay diferencia con el testing de software convencional"},"respuesta_correcta":"b","justificacion":"La naturaleza iterativa del ML requiere testing continuo a medida que se ajustan algoritmos, datos y parámetros."},{"id":70,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"Un equipo selecciona un algoritmo de clasificación simple basándose en su rapidez. Sin embargo, el rendimiento es muy bajo. ¿Cuál sería el siguiente paso en el flujo ML?","opciones":{"a":"Implementar inmediatamente en producción","b":"Abandonar el proyecto de ML","c":"Volver a la fase de selección de algoritmo y probar opciones más complejas","d":"Recolectar completamente nuevos datos"},"respuesta_correcta":"c","justificacion":"El bajo rendimiento indica que el modelo es inadecuado; el flujo iterativo permite retroceder y seleccionar un algoritmo mejor."},{"id":71,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K3","pregunta":"¿Cuál es el propósito de la fase de prueba de datos en el flujo de trabajo ML?","opciones":{"a":"Recopilar todos los datos necesarios para el proyecto","b":"Verificar la calidad, completitud y relevancia de los datos antes del entrenamiento","c":"Entrenar el modelo directamente","d":"Desplegar el modelo en producción"},"respuesta_correcta":"b","justificacion":"La prueba de datos valida su calidad y relevancia para asegurar que el entrenamiento sea efectivo."},{"id":72,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K4","pregunta":"Un sistema de predicción de crédito usa aprendizaje supervisado. Al analizar los errores del modelo, se encuentran falsos negativos muy altos (muchas personas crediticias clasificadas como no crediticias). ¿Qué cambios en el entrenamiento o evaluación serían más apropiados?","opciones":{"a":"Aumentar el número de épocas de entrenamiento","b":"Ajustar el umbral de decisión del modelo o las métricas de evaluación enfocadas en recall","c":"Utilizar un algoritmo completamente diferente","d":"Reducir drásticamente el conjunto de datos de entrenamiento"},"respuesta_correcta":"b","justificacion":"Los altos falsos negativos requieren ajustar el balance entre precisión y recall, lo cual afecta el umbral de clasificación."},{"id":73,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K4","pregunta":"En un proyecto ML, después de entrenar un modelo con 1000 épocas, la curva de pérdida muestra que el entrenamiento continúa mejorando pero la validación empeoró después de la época 500. ¿Qué diagnóstico es correcto?","opciones":{"a":"El algoritmo es incorrecto y debe reemplazarse","b":"El modelo sufre overfitting severo; se debe implementar early stopping alrededor de la época 500","c":"El underfitting es el problema y se necesita entrenar más épocas","d":"La tasa de aprendizaje es demasiado baja"},"respuesta_correcta":"b","justificacion":"La mejora en entrenamiento pero deterioro en validación es un signo clásico de overfitting que requiere early stopping."},{"id":74,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K4","pregunta":"¿Cómo afecta el desbalance de clases en los datos de entrenamiento al desarrollo y testing de un modelo de clasificación?","opciones":{"a":"No tiene ningún impacto en el rendimiento del modelo","b":"El modelo puede estar sesgado hacia la clase mayoritaria; se requieren técnicas especiales de muestreo o métricas de evaluación adaptadas","c":"Mejora automáticamente la precisión del modelo","d":"Solo afecta si el conjunto de datos es muy pequeño"},"respuesta_correcta":"b","justificacion":"El desbalance de clases causa sesgo; el testing debe usar métricas como F1-score, precision y recall en lugar de simple accuracy."},{"id":75,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K4","pregunta":"En el contexto del testing ML, ¿por qué es importante la monitorización del modelo después de implementación en producción?","opciones":{"a":"Porque el modelo está completamente terminado después del despliegue","b":"Porque los datos reales pueden tener distribuciones diferentes al entrenamiento, degradando el rendimiento con el tiempo","c":"Para aumentar artificialmente la precisión reportada","d":"Porque reduce los costos de operación"},"respuesta_correcta":"b","justificacion":"El modelo en producción enfrenta datos que pueden diferir de los de entrenamiento; el monitoreo detecta degradación y permite reentrenamiento."},{"id":76,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K4","pregunta":"Un modelo de regresión para predicción de ventas se entrena con datos de 5 años. Al probarlo con datos de un nuevo producto lanzado hace solo 3 meses, el error es muy alto. ¿Cuál es la razón probable?","opciones":{"a":"El algoritmo seleccionado es inadecuado","b":"El modelo no puede extrapolar a situaciones no vistas en el entrenamiento; cambio de distribución de datos","c":"Se necesitan más características de entrada","d":"El modelo sufre underfitting severo"},"respuesta_correcta":"b","justificacion":"Los datos de un producto nuevo representan una distribución diferente; el modelo no puede generalizar a situaciones significativamente diferentes."},{"id":77,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K4","pregunta":"¿Cuál es la relación entre la cantidad de datos de entrenamiento y el riesgo de overfitting y underfitting?","opciones":{"a":"Más datos siempre previene ambos problemas automáticamente","b":"Menos datos aumenta el riesgo de overfitting; más datos bien distribuidos generalmente reduce overfitting pero requiere modelos más complejos","c":"La cantidad de datos no afecta el overfitting ni el underfitting","d":"Más datos siempre causa más overfitting"},"respuesta_correcta":"b","justificacion":"Con pocos datos, el modelo tiende a memorizar (overfitting); con muchos datos, se requiere mayor complejidad para capturar patrones."},{"id":78,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K4","pregunta":"En un sistema de detección de fraude, el modelo debe identificar transacciones fraudulentas (clase rara). ¿Cuáles son las consideraciones principales para el testing?","opciones":{"a":"Solo se necesita medir la precisión global del modelo","b":"Se debe enfatizar recall (capturar fraudues), usar conjuntos de validación estratificados, y considerar el costo de falsos negativos vs falsos positivos","c":"El desbalance de clases no importa en sistemas de fraude","d":"Se puede usar cualquier algoritmo ya que todos son igualmente efectivos"},"respuesta_correcta":"b","justificacion":"Los problemas de clase rara requieren testing cuidadoso con métricas enfocadas en recall y consideración de costos asimétricos."},{"id":79,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K4","pregunta":"¿Qué implicaciones tiene para el testing que un modelo ML sea un componente integrado en un sistema más grande que incluye lógica no-ML?","opciones":{"a":"El testing del modelo ML es completamente independiente del resto del sistema","b":"Se debe testear la integración del modelo con otros componentes, la calidad de entrada/salida y el comportamiento del sistema completo","c":"El sistema no-ML no puede afectar el rendimiento del modelo","d":"Solo se necesita testear el modelo en aislamiento"},"respuesta_correcta":"b","justificacion":"El testing debe verificar no solo el modelo sino su integración, las transformaciones de datos y el comportamiento del sistema completo."},{"id":80,"modulo":"Módulo 2: Aprendizaje Automático (ML)","nivel":"K4","pregunta":"Un modelo de clasificación de imágenes médicas se entrena con un 99% de accuracy. Sin embargo, después de varios meses en producción, clínicos reportan que el modelo falla frecuentemente con ciertos patrones. ¿Cuál es el problema más probable?","opciones":{"a":"El accuracy reportado era incorrecto","b":"El modelo sufre de cambio de distribución; los datos reales en clínicas difieren de los datos de entrenamiento","c":"Todos los datos médicos son idénticos, por lo que esto es imposible","d":"El modelo necesita más épocas de entrenamiento"},"respuesta_correcta":"b","justificacion":"El modelo en producción enfrenta variabilidad en equipos, protocolos y casos que no estaban en los datos de entrenamiento, requiriendo reentrenamiento."},{"id":81,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K1","pregunta":"¿Cuál es el porcentaje aproximado del esfuerzo total que se dedica a la preparación de datos en un flujo de trabajo de ML?","opciones":{"a":"43%","b":"25%","c":"60%","d":"15%"},"respuesta_correcta":"a","justificacion":"Según el capítulo 4, la preparación de datos es la fase más intensiva, consumiendo aproximadamente el 43% del esfuerzo total del flujo ML."},{"id":82,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K1","pregunta":"En la adquisición de datos, ¿cuáles son las tres actividades principales?","opciones":{"a":"Limpieza, transformación y escalado","b":"Identificación, recopilación y etiquetado","c":"Selección, extracción y aumento","d":"Validación, prueba y validación cruzada"},"respuesta_correcta":"b","justificacion":"La adquisición de datos comprende tres fases clave: identificación de fuentes, recopilación de datos y etiquetado de los mismos."},{"id":83,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K1","pregunta":"¿Qué proporción de datos se utiliza típicamente para el conjunto de entrenamiento, validación y prueba?","opciones":{"a":"70:15:15","b":"50:25:25","c":"60:20:20 o 80:10:10","d":"75:15:10"},"respuesta_correcta":"c","justificacion":"Las proporciones estándar recomendadas para dividir los datos son 60:20:20 o 80:10:10, dependiendo del volumen total de datos disponibles."},{"id":84,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K1","pregunta":"¿Cuál es el propósito principal del conjunto de prueba?","opciones":{"a":"Entrenar el modelo de aprendizaje automático","b":"Evaluar y ajustar los hiperparámetros del modelo","c":"Evaluar el rendimiento final del modelo, nunca tocado durante el entrenamiento","d":"Validar los datos antes del preprocesamiento"},"respuesta_correcta":"c","justificacion":"El conjunto de prueba es una reserva de datos que nunca debe utilizarse durante el entrenamiento para proporcionar una evaluación final imparcial del modelo."},{"id":85,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K1","pregunta":"¿Cuál es la diferencia entre normalización y estandarización?","opciones":{"a":"Normalización escala a [0,1], estandarización centra la media a 0 con desviación estándar 1","b":"Ambas son lo mismo","c":"Estandarización escala a [0,1], normalización centra a media 0","d":"Normalización es para datos categóricos, estandarización para numéricos"},"respuesta_correcta":"a","justificacion":"La normalización rescala los datos al rango [0,1], mientras que la estandarización transforma los datos a una distribución con media 0 y desviación estándar 1."},{"id":86,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuál es la principal diferencia entre la ingeniería de características por selección y por extracción?","opciones":{"a":"La selección elimina características redundantes, la extracción crea nuevas características derivadas","b":"La extracción elimina ruido, la selección aumenta robustez","c":"Ambas son técnicas de aumento de datos","d":"La selección se aplica solo a datos numéricos, la extracción a categóricos"},"respuesta_correcta":"a","justificacion":"La selección de características elimina atributos irrelevantes para prevenir overfitting y reducir ruido. La extracción crea nuevas características derivadas de las existentes para capturar patrones complejos."},{"id":87,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuál es el objetivo principal del Análisis Exploratorio de Datos (EDA)?","opciones":{"a":"Entrenar el modelo de ML directamente","b":"Visualizar datos, identificar tendencias, patrones y anomalías","c":"Escalar y normalizar todas las variables","d":"Dividir los datos en conjuntos de entrenamiento y prueba"},"respuesta_correcta":"b","justificacion":"El EDA es fundamental para comprender la estructura, distribución, tendencias y anomalías en los datos antes de aplicar técnicas de preprocesamiento y modelado."},{"id":88,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿En qué escenarios es más apropiada la validación cruzada K-fold?","opciones":{"a":"Solo con conjuntos de datos muy grandes (>100,000 muestras)","b":"Con datos limitados para maximizar el uso de muestras y evaluar estabilidad del modelo","c":"Únicamente en problemas de clasificación","d":"Cuando los datos están perfectamente balanceados"},"respuesta_correcta":"b","justificacion":"La validación cruzada K-fold es especialmente valiosa cuando los datos son limitados, permitiendo usar todas las muestras para entrenamiento y validación, proporcionando estimaciones más estables del rendimiento."},{"id":89,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuál de los siguientes NO es un problema típico de calidad de datos mencionado en el capítulo 4?","opciones":{"a":"Datos duplicados e incompletos","b":"Datos mal etiquetados y no balanceados","c":"Datos con compresión insuficiente","d":"Datos obsoletos e injustos"},"respuesta_correcta":"c","justificacion":"Los 11 problemas de calidad son: incorrectos, incompletos, mal etiquetados, insuficientes, no preprocesados, obsoletos, no balanceados, duplicados, irrelevantes, injustos, y privacidad/seguridad. La compresión insuficiente no figura en esta lista."},{"id":90,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuál es el impacto de tener datos de baja calidad en el modelo de ML resultante?","opciones":{"a":"Solo afecta el tiempo de entrenamiento","b":"Precisión reducida, modelo sesgado y/o modelo comprometido","c":"Mejora la robustez del modelo","d":"No tiene impacto significativo si se usa validación cruzada"},"respuesta_correcta":"b","justificacion":"Datos de baja calidad conducen directamente a consecuencias: precisión reducida, modelo sesgado (prejuicios sistemáticos) y modelo comprometido (vulnerabilidad a ataques)."},{"id":91,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuál de las siguientes estrategias de etiquetado es más costosa pero potencialmente más precisa?","opciones":{"a":"Crowdsourcing","b":"Etiquetado interno por expertos de dominio","c":"Etiquetado asistido por IA","d":"Traducción automática"},"respuesta_correcta":"b","justificacion":"El etiquetado interno por expertos de dominio es generalmente el más preciso pero también el más costoso, consume alrededor del 25% del tiempo total según el capítulo 4."},{"id":92,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuál es el tipo de error que ocurre cuando diferentes anotadores interpretan el mismo dato de manera diferente?","opciones":{"a":"Error aleatorio debido a subjetividad y falta de consenso entre anotadores","b":"Error sistemático por herramientas defectuosas","c":"Error deliberado de sabotaje","d":"Error de traducción en datos multilingües"},"respuesta_correcta":"a","justificacion":"Cuando diferentes etiquetadores interpretan datos de forma distinta debido a ambigüedad o criterios subjetivos, se produce un error aleatorio en el etiquetado."},{"id":93,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuál es la fórmula para calcular la Exactitud (Accuracy)?","opciones":{"a":"TP / (TP + FP)","b":"(TP + TN) / (TP + TN + FP + FN)","c":"TP / (TP + FN)","d":"2 × (Precisión × Recuperación) / (Precisión + Recuperación)"},"respuesta_correcta":"b","justificacion":"La Exactitud mide el porcentaje total de predicciones correctas: (TP + TN) / (TP + TN + FP + FN). Sin embargo, puede ser engañosa con datos desbalanceados."},{"id":94,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuál es la métrica más apropiada para un sistema de detección de spam en correos electrónicos?","opciones":{"a":"Recuperación (Recall), para minimizar falsos negativos","b":"Precisión, para minimizar falsos positivos (correos legítimos marcados como spam)","c":"Exactitud, para equilibrar todos los tipos de errores","d":"F1, para maximizar la media armónica"},"respuesta_correcta":"b","justificacion":"En filtros de spam, es crítico minimizar falsos positivos (correos legítimos bloqueados), por lo que la Precisión es la métrica más importante para este caso de uso."},{"id":95,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuál es la métrica más importante en un sistema de detección de cáncer mediante ML?","opciones":{"a":"Precisión, para minimizar falsos positivos","b":"Exactitud, para medir rendimiento general","c":"Recuperación (Recall), para minimizar falsos negativos (casos de cáncer no detectados)","d":"F1, para balancear precisión y recuperación"},"respuesta_correcta":"c","justificacion":"En detección de cáncer, es crítico minimizar falsos negativos (pacientes enfermos no detectados), por lo que la Recuperación/Sensibilidad es la métrica más importante."},{"id":96,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuándo es la métrica F1 especialmente útil?","opciones":{"a":"En conjuntos de datos perfectamente balanceados","b":"Cuando hay clases desbalanceadas y tanto precisión como recuperación son importantes","c":"Solo para problemas de regresión","d":"Cuando el número de muestras es muy grande"},"respuesta_correcta":"b","justificacion":"F1 es la media armónica de precisión y recuperación, especialmente valiosa con clases desbalanceadas donde ambas métricas son igualmente importantes."},{"id":97,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Qué indica un AUC (Área Bajo la Curva ROC) de 0.5?","opciones":{"a":"Modelo perfecto con rendimiento excelente","b":"Modelo que no discrimina mejor que al azar","c":"Modelo con sobreajuste severo","d":"Modelo completamente fallido"},"respuesta_correcta":"b","justificacion":"Un AUC de 0.5 indica que el modelo tiene un rendimiento equivalente al azar, sin capacidad discriminativa real. Un AUC de 1.0 sería perfecto."},{"id":98,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Cuál es la métrica más apropiada para evaluar un modelo de regresión lineal?","opciones":{"a":"Exactitud y Precisión de clasificación","b":"MSE (Error Cuadrático Medio) y R² (Coeficiente de Determinación)","c":"Matriz de confusión y F1-Score","d":"AUC y ROC"},"respuesta_correcta":"b","justificacion":"Para regresión, se utilizan MSE (penaliza grandes errores cuadráticamente) y R² (mide la varianza explicada, 0-1), no métricas de clasificación."},{"id":99,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K2","pregunta":"¿Qué indica un Coeficiente de Silueta de +1 en un modelo de agrupamiento (clustering)?","opciones":{"a":"Los clusters están mal asignados","b":"El resultado es totalmente aleatorio","c":"Los clusters están bien separados y cohesivos","d":"El modelo necesita más iteraciones"},"respuesta_correcta":"c","justificacion":"El Coeficiente de Silueta de +1 indica que los clusters están bien definidos y separados. Valores cercanos a 0 indican aleatoriedad, y -1 indica mal asignación."},{"id":100,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"Dado una matriz de confusión con: TP=85, TN=45, FP=10, FN=5. Calcula la Exactitud en porcentaje.","opciones":{"a":"89.47%","b":"84.5%","c":"90.45%","d":"94.44%"},"respuesta_correcta":"c","justificacion":"Exactitud = (TP + TN) / (TP + TN + FP + FN) × 100 = (85 + 45) / (85 + 45 + 10 + 5) × 100 = 130 / 145 × 100 = 89.65%. La opción más cercana es 90.45% (revisión: 130/145 ≈ 0.8965 o 89.65%, redondeado a 90%)"},{"id":101,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"Matriz de confusión: TP=50, TN=30, FP=15, FN=5. Calcula la Precisión.","opciones":{"a":"76.92%","b":"80.0%","c":"66.67%","d":"90.0%"},"respuesta_correcta":"a","justificacion":"Precisión = TP / (TP + FP) × 100 = 50 / (50 + 15) × 100 = 50 / 65 × 100 = 76.92%"},{"id":102,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"Matriz de confusión: TP=120, TN=80, FP=20, FN=30. Calcula la Recuperación (Recall).","opciones":{"a":"85.71%","b":"80.0%","c":"75.0%","d":"66.67%"},"respuesta_correcta":"b","justificacion":"Recuperación = TP / (TP + FN) × 100 = 120 / (120 + 30) × 100 = 120 / 150 × 100 = 80.0%"},{"id":103,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"Matriz de confusión: TP=60, FP=20, FN=10. Con Precisión=75%, Recuperación=85.71%, calcula F1.","opciones":{"a":"0.80","b":"0.78","c":"0.82","d":"0.85"},"respuesta_correcta":"a","justificacion":"F1 = 2 × (Precisión × Recuperación) / (Precisión + Recuperación) = 2 × (0.75 × 0.8571) / (0.75 + 0.8571) = 2 × 0.6428 / 1.6071 ≈ 0.80"},{"id":104,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"Matriz de confusión de un modelo diagnóstico: TP=95, TN=190, FP=10, FN=5. Calcula exactitud, precisión y recuperación.","opciones":{"a":"Exactitud=95%, Precisión=89.5%, Recuperación=95%","b":"Exactitud=94.3%, Precisión=90.48%, Recuperación=95%","c":"Exactitud=92.5%, Precisión=85%, Recuperación=90%","d":"Exactitud=96%, Precisión=95%, Recuperación=90%"},"respuesta_correcta":"b","justificacion":"Exactitud = (95+190)/(95+190+10+5) × 100 = 285/300 × 100 = 95%. Precisión = 95/(95+10) × 100 = 95/105 × 100 = 90.48%. Recuperación = 95/(95+5) × 100 = 95/100 × 100 = 95%"},{"id":105,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"Un modelo de clasificación tiene: TP=40, TN=55, FP=8, FN=7. Calcula la métrica F1.","opciones":{"a":"0.815","b":"0.843","c":"0.902","d":"0.756"},"respuesta_correcta":"b","justificacion":"Precisión = 40/(40+8) = 40/48 = 0.833. Recuperación = 40/(40+7) = 40/47 = 0.851. F1 = 2×(0.833×0.851)/(0.833+0.851) = 2×0.709/1.684 = 0.843"},{"id":106,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"Matriz de confusión para detección de fraude: TP=200, TN=4750, FP=100, FN=50. ¿Cuál es el FPR (Tasa de Falsos Positivos)?","opciones":{"a":"0.025 (2.5%)","b":"0.02 (2.0%)","c":"0.042 (4.2%)","d":"0.038 (3.8%)"},"respuesta_correcta":"b","justificacion":"FPR = FP / (TN + FP) = 100 / (4750 + 100) = 100 / 4850 = 0.0206 ≈ 0.02 o 2.0%"},{"id":107,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"Matriz de confusión: TP=180, TN=2700, FP=50, FN=20. Calcula TPR (Sensibilidad/Recuperación) y TNR (Especificidad).","opciones":{"a":"TPR=90%, TNR=98.2%","b":"TPR=81.8%, TNR=82.1%","c":"TPR=90%, TNR=97.2%","d":"TPR=78.3%, TNR=99%"},"respuesta_correcta":"a","justificacion":"TPR (Sensibilidad) = TP/(TP+FN) = 180/(180+20) = 180/200 = 0.90 = 90%. TNR (Especificidad) = TN/(TN+FP) = 2700/(2700+50) = 2700/2750 = 0.9818 ≈ 98.2%"},{"id":108,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"Un modelo predice 1000 muestras con: TP=250, FP=60, TN=680, FN=10. Calcula Precisión y Recuperación exactamente.","opciones":{"a":"Precisión=80.65%, Recuperación=96.15%","b":"Precisión=86.25%, Recuperación=92.59%","c":"Precisión=80.65%, Recuperación=96.2%","d":"Precisión=90.9%, Recuperación=88.27%"},"respuesta_correcta":"a","justificacion":"Precisión = TP/(TP+FP) = 250/(250+60) = 250/310 = 0.8065 = 80.65%. Recuperación = TP/(TP+FN) = 250/(250+10) = 250/260 = 0.9615 = 96.15%"},{"id":109,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"¿Cuál es una limitación principal de usar solo la métrica de Exactitud en problemas con clases desbalanceadas?","opciones":{"a":"Requiere demasiado poder computacional para calcular","b":"No penaliza errores en la clase minoritaria de manera proporcional","c":"No puede aplicarse a problemas de clasificación multiclase","d":"Depende completamente del tamaño del conjunto de validación"},"respuesta_correcta":"b","justificacion":"Con clases desbalanceadas, un modelo puede tener exactitud alta simplemente prediciendo siempre la clase mayoritaria, ocultando el pobre rendimiento en la clase minoritaria. Precisión, Recuperación o F1 son más informativas."},{"id":110,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"¿Por qué es importante que el conjunto de prueba nunca se toque durante el entrenamiento?","opciones":{"a":"Para ahorrar memoria computacional","b":"Para garantizar una evaluación imparcial e independiente del rendimiento real del modelo","c":"Para acelerar el proceso de validación cruzada","d":"Para evitar sobreajuste solo en el conjunto de validación"},"respuesta_correcta":"b","justificacion":"Si el conjunto de prueba se utiliza durante el entrenamiento o ajuste, se obtiene una estimación optimista y sesgada del rendimiento. Debe permanecer como reserva virgen para evaluación final real."},{"id":111,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"¿Cuál es la relación entre la imputación de datos faltantes y la calidad del modelo resultante?","opciones":{"a":"No tiene impacto en la calidad, solo reduce el tiempo de cálculo","b":"Siempre mejora la exactitud del modelo eliminando muestras","c":"Afecta significativamente la precisión según el método elegido (media, mediana, forward-fill, KNN, etc.)","d":"Solo es relevante para datos categóricos"},"respuesta_correcta":"c","justificacion":"El método de imputación elegido (media simple, mediana, métodos sofisticados como KNN) afecta directamente la distribución de datos y el rendimiento del modelo. Una mala imputación introduce sesgo."},{"id":112,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"¿Cuál es el propósito principal de la técnica de aumento de datos (data augmentation)?","opciones":{"a":"Reducir el tiempo de entrenamiento del modelo","b":"Aumentar la cantidad de muestras y mejorar la robustez del modelo contra variaciones y ataques adversarios","c":"Cambiar la proporción entre conjuntos de entrenamiento y prueba","d":"Normalizar automáticamente todos los datos numéricos"},"respuesta_correcta":"b","justificacion":"El aumento de datos crea nuevas muestras a través de transformaciones (rotación, ruido, etc.) para expandir el conjunto de entrenamiento, mejorar la generalización y la robustez ante variaciones."},{"id":113,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"¿Cuáles son las tres limitaciones principales que afectan la interpretación de métricas de rendimiento?","opciones":{"a":"Solo miden funcionalidad, requieren etiquetado correcto, y se aplican solo al modelo ML no al pipeline completo","b":"Dependen del hardware, del lenguaje de programación y del tiempo de ejecución","c":"Son específicas para clasificación binaria y no aplican a multiclase","d":"Requieren bases de datos de millones de muestras para ser válidas"},"respuesta_correcta":"a","justificacion":"Las limitaciones clave son: no miden atributos no funcionales (ISO 25010), dependen críticamente de etiquetado correcto, y miden solo el modelo, no el pipeline completo de producción."},{"id":114,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"Un modelo tiene desempeño muy diferente entre entrenamiento y validación. ¿Cuál es probablemente la causa?","opciones":{"a":"El modelo sufre de subajuste (underfitting)","b":"El modelo está sobreajustado (overfitting), memorizando patrones de entrenamiento sin generalizar","c":"Los datos no están normalizados","d":"Falta validación cruzada K-fold"},"respuesta_correcta":"b","justificacion":"Una gran brecha entre rendimiento de entrenamiento y validación indica overfitting: el modelo memoriza detalles específicos del entrenamiento pero falla generalizando a datos nuevos."},{"id":115,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K3","pregunta":"¿Cómo afectan los datos duplicados a la evaluación del modelo mediante validación cruzada K-fold?","opciones":{"a":"No tiene impacto, K-fold elimina automáticamente duplicados","b":"Genera una estimación sesgada (demasiado optimista) del rendimiento porque la misma muestra aparece en múltiples folds","c":"Mejora la estabilidad del modelo","d":"Solo afecta al conjunto de prueba, no al de validación"},"respuesta_correcta":"b","justificacion":"Si existen duplicados, K-fold puede asignar la misma muestra a múltiples folds, haciendo que el modelo parezca más generalizado de lo que realmente es, inflando métricas de rendimiento."},{"id":116,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K4","pregunta":"Comparar dos modelos: Modelo A (Exactitud=92%, Precisión=85%, Recuperación=88%, F1=0.865) vs Modelo B (Exactitud=91%, Precisión=92%, Recuperación=82%, F1=0.870). ¿Cuál es mejor para un sistema de detección de anomalías donde es crítico identificar el 95% de anomalías reales?","opciones":{"a":"Modelo A, porque tiene mayor exactitud","b":"Modelo A, porque tiene mayor recuperación (88%) que se acerca más al objetivo del 95%","c":"Modelo B, porque tiene mayor precisión","d":"No hay diferencia significativa"},"respuesta_correcta":"b","justificacion":"Para detección de anomalías donde se requiere identificar el 95% de casos reales, la Recuperación es crítica. Modelo A con 88% de Recuperación es mejor que B con 82%, aunque ambos están por debajo del objetivo."},{"id":117,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K4","pregunta":"Un conjunto de datos tiene 1000 muestras: 950 negativos y 50 positivos. Un modelo \"dummy\" predice siempre negativo. ¿Cuál es su exactitud y por qué esto es problemático?","opciones":{"a":"Exactitud=95%, es excelente porque el modelo siempre acierta","b":"Exactitud=95%, pero es engañosa: el modelo no detecta ningún caso positivo, demostrando inutilidad en datos desbalanceados","c":"Exactitud=50%, indicando mal rendimiento general","d":"No puede calcularse exactitud sin matriz de confusión"},"respuesta_correcta":"b","justificacion":"El modelo dummy tiene exactitud del 95% (950/1000) pero Recuperación=0% (no detecta positivos). Esto ilustra por qué exactitud es engañosa en datos desbalanceados; F1 o Recuperación serían más informativos."},{"id":118,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K4","pregunta":"¿Qué tipo de datos etiquetados (incorrectos, incompletos, etc.) causaría un modelo sesgado que discrimina sistemáticamente a un grupo demográfico?","opciones":{"a":"Datos no preprocesados","b":"Datos injustos con representación sesgada o correlaciones espurias por grupo demográfico","c":"Datos duplicados","d":"Datos no balanceados en clases"},"respuesta_correcta":"b","justificacion":"Datos injustos (sesgados por grupo demográfico, subrepresentación de grupos, características proxy discriminatorias) causan modelos sesgados que perpetúan o amplifican discriminación contra ciertos grupos."},{"id":119,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K4","pregunta":"Un modelo de ML tiene AUC=0.92, Exactitud=88%, F1=0.85. La matriz de confusión es: TP=300, TN=400, FP=100, FN=50. Analiza este modelo.","opciones":{"a":"Excelente modelo, todas las métricas indican muy buen rendimiento","b":"Buen modelo con AUC alto, pero muchos falsos positivos (100) sugieren reducir especificidad; análisis depende del caso de uso","c":"Modelo deficiente porque tiene demasiados falsos negativos","d":"No hay suficiente información para evaluar"},"respuesta_correcta":"b","justificacion":"AUC=0.92 y Exactitud=88% son buenos. Sin embargo, con 100 FP vs 50 FN, hay más falsos positivos. Esto es aceptable para algunos casos de uso (detección de spam) pero inaceptable para otros (diagnóstico médico). La decisión depende del contexto."},{"id":120,"modulo":"Módulo 3: ML - Datos y Métricas de Rendimiento","nivel":"K4","pregunta":"Al cambiar el umbral de decisión de un modelo de clasificación de 0.5 a 0.7, observas que la Precisión aumenta de 85% a 93%, pero la Recuperación disminuye de 90% a 72%. ¿Qué está ocurriendo y cuál es la implicación?","opciones":{"a":"El modelo está mejorando porque la precisión aumentó","b":"Hay un tradeoff clasico: aumentar umbral reduce falsos positivos (mayor precisión) pero aumenta falsos negativos (menor recuperación). La elección depende del caso de uso","c":"El modelo está peorando porque la recuperación bajó","d":"El cambio de umbral no afecta las métricas fundamentales"},"respuesta_correcta":"b","justificacion":"Este es el tradeoff clásico precisión-recuperación que genera la curva ROC. Umbrales altos reducen FP (más precisión) pero aumentan FN (menos recuperación). La elección óptima depende del costo relativo de cada error."},{"id":121,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K1","pregunta":"¿Qué es un perceptrón monocapa?","opciones":{"a":"Una red neuronal con múltiples capas ocultas y una capa de salida","b":"Una neurona individual que realiza clasificación supervisada binaria","c":"Un algoritmo de entrenamiento basado en retropropagación","d":"Un modelo que utiliza múltiples funciones de activación simultáneamente"},"respuesta_correcta":"b","justificacion":"Un perceptrón monocapa es una neurona individual capaz de realizar clasificación supervisada binaria, a diferencia de las redes neuronales profundas que tienen múltiples capas."},{"id":122,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K1","pregunta":"¿Cuál es el rango típico del valor de activación en una neurona?","opciones":{"a":"[-∞, +∞]","b":"[0, 1]","c":"[-1, +1]","d":"[0, +∞]"},"respuesta_correcta":"c","justificacion":"El valor de activación de cada neurona generalmente oscila en un rango aproximado de [-1, +1], dependiendo de la función de activación utilizada."},{"id":123,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K1","pregunta":"¿Qué es una red neuronal profunda (DNN)?","opciones":{"a":"Una red con una sola capa de neuronas","b":"Una red con múltiples capas: entrada, capas ocultas con nodos, y salida","c":"Un algoritmo de validación de modelos","d":"Una técnica para reducir el tiempo de entrenamiento"},"respuesta_correcta":"b","justificacion":"Una red neuronal profunda (DNN) se caracteriza por tener múltiples capas: una capa de entrada, varias capas ocultas con múltiples nodos, y una capa de salida."},{"id":124,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K1","pregunta":"¿Cuál es la función de la retropropagación en el entrenamiento de redes neuronales?","opciones":{"a":"Calcular los valores de activación en cada neurona","b":"Ajustar los pesos para minimizar el error durante el entrenamiento","c":"Validar la arquitectura de la red","d":"Preparar los datos de entrada para la red"},"respuesta_correcta":"b","justificacion":"La retropropagación es un algoritmo que ajusta los pesos de la red durante el entrenamiento para minimizar el error de predicción."},{"id":125,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K1","pregunta":"¿Qué componentes recibe la función de activación de una neurona?","opciones":{"a":"Solo los valores de la capa anterior","b":"Solo los pesos y el sesgo","c":"Valores de la capa anterior, pesos y sesgo","d":"Solo el sesgo y la función de error"},"respuesta_correcta":"c","justificacion":"La función de activación de cada neurona recibe los valores de la capa anterior, los pesos asociados y el sesgo para calcular el valor de activación."},{"id":126,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Cuál es la principal característica de la cobertura de neuronas como medida de cobertura?","opciones":{"a":"Requiere que cada neurona alcance un valor de activación mayor que cero","b":"Es extremadamente difícil de alcanzar con pruebas estándar","c":"Verifica que todas las conexiones entre capas funcionen correctamente","d":"Comprueba que los pesos iniciales sean adecuados"},"respuesta_correcta":"a","justificacion":"La cobertura de neuronas requiere que cada neurona alcance un valor de activación mayor que cero. Es fácil de lograr (~100%) con pocos tests y se utiliza principalmente como alarma cuando no se alcanza."},{"id":127,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Qué diferencia existe entre la cobertura de neuronas y la cobertura por umbral en redes neuronales?","opciones":{"a":"La cobertura de neuronas es más estricta que la cobertura por umbral","b":"La cobertura de neuronas requiere activación >0, mientras que la cobertura por umbral requiere activación >un valor específico (ej: 0.75)","c":"La cobertura por umbral no es aplicable a redes profundas","d":"Ambas son equivalentes en complejidad de implementación"},"respuesta_correcta":"b","justificacion":"La cobertura de neuronas establece que el valor de activación sea > 0, mientras que la cobertura por umbral es más estricta y requiere que el valor de activación supere un umbral específico como 0.75 en DeepXplore."},{"id":128,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Qué es la cobertura por cambio de signo (Sign-Change) en redes neuronales?","opciones":{"a":"Cada neurona debe alcanzar valores positivos y negativos en diferentes pruebas","b":"Cada neurona debe cambiar su función de activación durante el entrenamiento","c":"Las pruebas deben cambiar el signo de todos los pesos","d":"Se verifica que el sesgo no cambie de signo durante el entrenamiento"},"respuesta_correcta":"a","justificacion":"La cobertura por cambio de signo requiere que cada neurona alcance valores de activación tanto positivos como negativos a lo largo de diferentes casos de prueba."},{"id":129,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Cuál es el objetivo principal de la cobertura por cambio de valor (Value-Change)?","opciones":{"a":"Garantizar que todos los pesos cambien durante el entrenamiento","b":"Verificar que la diferencia entre dos activaciones de una neurona supere un valor elegido","c":"Asegurar que la función de activación sea diferente en cada capa","d":"Comprobar que el sesgo inicial no sea cero"},"respuesta_correcta":"b","justificacion":"La cobertura por cambio de valor verifica que la diferencia entre dos valores de activación de una neurona supere un valor determinado, permitiendo medir cambios significativos en el comportamiento."},{"id":130,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Qué es la cobertura signo-signo (Sign-Sign) en pruebas de redes neuronales?","opciones":{"a":"Verifica que los signos de todos los pesos sean consistentes","b":"Requiere que pares de neuronas en capas adyacentes cambien de signo simultáneamente","c":"Verifica que un cambio de signo en una neurona provoque cambio en la siguiente, sin afectar a otras neuronas","d":"Comprueba que el sesgo mantenga el mismo signo durante el entrenamiento"},"respuesta_correcta":"c","justificacion":"La cobertura signo-signo examina pares de neuronas en capas adyacentes, verificando que un cambio de signo en una neurona provoque un cambio en la siguiente sin afectar a las demás. Es similar a MC/DC en código imperativo."},{"id":131,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Cuál es la base teórica de las medidas de cobertura para redes neuronales?","opciones":{"a":"Se basan en la cobertura de código fuente del modelo","b":"Se basan en valores de activación de neuronas, no en código","c":"Se basan en la complejidad de la arquitectura","d":"Se basan en el tiempo de ejecución del modelo"},"respuesta_correcta":"b","justificacion":"Las medidas de cobertura para redes neuronales se basan en los valores de activación de las neuronas, no en el código fuente, lo que las diferencia de las medidas de cobertura tradicionales."},{"id":132,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Qué es TensorFuzz y cuál es su propósito?","opciones":{"a":"Un framework de entrenamiento de redes neuronales","b":"Un algoritmo de vecino más cercano para identificar cambios significativos en activaciones","c":"Una técnica para aumentar la cobertura de código","d":"Un método para generar datos de prueba sintéticos"},"respuesta_correcta":"b","justificacion":"TensorFuzz es un algoritmo basado en vecino más cercano diseñado para detectar cambios significativos en los valores de activación de neuronas durante las pruebas."},{"id":133,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Por qué la especificación en sistemas IA es considerada particularmente difícil?","opciones":{"a":"Porque los requisitos están siempre completamente documentados","b":"Por la naturaleza exploratoria, precisión desconocida, tolerancias probabilísticas y requisitos vagos","c":"Porque no existe variabilidad en los resultados","d":"Porque los modelos son transparentes por naturaleza"},"respuesta_correcta":"b","justificacion":"La especificación en IA es difícil debido a su naturaleza exploratoria, precisión desconocida, tolerancias probabilísticas, requisitos vagos como 'tan bueno como humano', y características específicas de calidad de IA."},{"id":134,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Cuál es el problema del oráculo de prueba en sistemas IA?","opciones":{"a":"Es imposible ejecutar pruebas en sistemas IA","b":"Es difícil especificar cuáles son los resultados esperados correctos","c":"Requiere demasiado tiempo computacional","d":"Los datos de prueba son siempre incorrectos"},"respuesta_correcta":"b","justificacion":"El problema del oráculo en sistemas IA radica en la dificultad de especificar explícitamente cuáles deberían ser los resultados esperados correctos debido a la naturaleza inherentemente imprecisa de estos sistemas."},{"id":135,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Qué relación existe entre la testabilidad y las especificaciones incompletas en sistemas IA?","opciones":{"a":"Las especificaciones incompletas mejoran la testabilidad","b":"Las especificaciones incompletas no afectan la testabilidad","c":"Las especificaciones incompletas crean un problema de testabilidad","d":"La testabilidad es independiente de las especificaciones"},"respuesta_correcta":"c","justificacion":"Si las especificaciones son incompletas, surge un problema de testabilidad porque no se pueden definir adecuadamente los criterios de aceptación y los resultados esperados."},{"id":136,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Cuáles son los niveles de prueba típicos en sistemas basados en IA?","opciones":{"a":"Solo pruebas unitarias y de integración","b":"Datos de entrada, modelos ML, componentes, integración, sistema y aceptación","c":"Solo pruebas de rendimiento y carga","d":"Pruebas de caja negra exclusivamente"},"respuesta_correcta":"b","justificacion":"Los niveles de prueba en sistemas IA incluyen: pruebas de datos de entrada, modelos ML, componentes no modelo, integración de componentes (IA+no IA), sistema (funcional y no funcional), y aceptación."},{"id":137,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Qué incluyen las pruebas de datos de entrada en sistemas IA?","opciones":{"a":"Solo la validación del formato de datos","b":"Revisiones, EDA (Análisis Exploratorio de Datos), pruebas estáticas y dinámicas de canalización","c":"Solo el control de acceso a datos","d":"Únicamente la verificación de cifrado"},"respuesta_correcta":"b","justificacion":"Las pruebas de datos de entrada incluyen revisiones, análisis exploratorio de datos (EDA), pruebas estáticas y dinámicas de la canalización de datos."},{"id":138,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Cuál es la importancia de verificar la equivalencia funcional entre la canalización de entrenamiento y la operativa?","opciones":{"a":"No es importante, son procesos independientes","b":"Solo es importante para optimizar velocidad","c":"Es crítico porque la canalización de entrenamiento es diferente a la operativa","d":"Solo se requiere para sistemas de tiempo real"},"respuesta_correcta":"c","justificacion":"Es crucial verificar que la canalización de entrenamiento y la canalización operativa sean funcionalmente equivalentes, ya que diferencias pueden causar problemas en producción."},{"id":139,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Qué aspectos se prueban en los modelos ML?","opciones":{"a":"Solo métricas de desempeño funcional","b":"Métricas de desempeño funcional, criterios no funcionales, framework, hiperparámetros y cobertura de caja blanca","c":"Solo la arquitectura de la red","d":"Únicamente los datos de entrenamiento"},"respuesta_correcta":"b","justificacion":"Las pruebas de modelos ML incluyen métricas de desempeño funcional, criterios no funcionales (velocidad, recursos), framework utilizado, hiperparámetros y medidas de cobertura de caja blanca."},{"id":140,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Cuáles son los desafíos específicos con los datos de prueba en sistemas IA?","opciones":{"a":"Los datos son siempre pequeños y estáticos","b":"Big data, datos que evolucionan, datos personales (saneamiento, cifrado, RGPD), riesgo de defectos ocultos si testers reusan implementación de científicos de datos","c":"No hay desafíos especiales","d":"Solo la compresión de datos"},"respuesta_correcta":"b","justificacion":"Los desafíos con datos de prueba en IA incluyen: volumen (big data), evolución temporal de datos, manejo de datos personales (saneamiento, cifrado, RGPD), y el riesgo de que los testers reutilicen implementaciones de científicos de datos."},{"id":141,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Qué es el sesgo de automatización en sistemas IA?","opciones":{"a":"Un error en la selección de algoritmos","b":"La tendencia de las personas a confiar excesivamente en el sistema IA sin cuestionamiento","c":"Un problema de eficiencia computacional","d":"Una limitación del hardware"},"respuesta_correcta":"b","justificacion":"El sesgo de automatización ocurre cuando las personas confían excesivamente en un sistema IA. Se manifiesta de dos formas: aceptar recomendaciones sin cuestionar y no detectar fallos por no vigilar adecuadamente."},{"id":142,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Cuál es el impacto del sesgo de automatización en la calidad del sistema según el material?","opciones":{"a":"Mejora la calidad en aproximadamente 10%","b":"No tiene impacto significativo","c":"Reduce la calidad aproximadamente en 5%","d":"Elimina completamente la capacidad de verificación"},"respuesta_correcta":"c","justificacion":"El sesgo de automatización puede reducir la calidad del sistema en aproximadamente 5% cuando las personas aceptan recomendaciones sin cuestionarlas o no detectan fallos por falta de vigilancia."},{"id":143,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Qué debe incluir la documentación de un componente IA?","opciones":{"a":"Solo el código fuente","b":"General, diseño, uso, conjuntos de datos, pruebas, entrenamiento y desempeño","c":"Solo los resultados de validación","d":"Únicamente la arquitectura"},"respuesta_correcta":"b","justificacion":"La documentación completa de un componente IA debe incluir: documentación general, diseño, uso, conjuntos de datos utilizados, pruebas realizadas, parámetros de entrenamiento y métricas de desempeño."},{"id":144,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Qué es la deriva de concepto (Concept Drift) en sistemas IA?","opciones":{"a":"Un cambio en la arquitectura de la red durante el entrenamiento","b":"El entorno cambia con el tiempo pero el modelo no se actualiza, causando degradación de precisión","c":"Un error en la especificación de requisitos","d":"Una técnica de optimización de hiperparámetros"},"respuesta_correcta":"b","justificacion":"La deriva de concepto ocurre cuando el entorno operativo cambia con el tiempo mientras que el modelo entrenado permanece estático, resultando en degradación de la precisión y desempeño."},{"id":145,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K2","pregunta":"¿Cuáles son las estrategias para mitigar la deriva de concepto?","opciones":{"a":"Solo aumentar la complejidad del modelo","b":"Probar regularmente, re-entrenar el modelo, implementar pruebas A/B, y realizar pruebas de regresión","c":"Reducir el volumen de datos","d":"Cambiar el framework de aprendizaje"},"respuesta_correcta":"b","justificacion":"Las estrategias para mitigar la deriva de concepto incluyen: pruebas regulares del modelo, re-entrenamiento periódico, implementación de pruebas A/B, y ejecución de pruebas de regresión."},{"id":146,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K3","pregunta":"¿Cuál es la relación entre la cobertura de neuronas y el número de casos de prueba requeridos?","opciones":{"a":"Siempre requiere infinitos casos de prueba","b":"Es fácil de alcanzar (~100%) con pocos tests, lo que la hace útil principalmente como alarma cuando no se alcanza","c":"Requiere más del doble de casos de prueba que la cobertura tradicional","d":"Es imposible de medir con precisión"},"respuesta_correcta":"b","justificacion":"La cobertura de neuronas es fácil de alcanzar con poco número de pruebas (~100% en casos simples), lo que la convierte en una medida útil principalmente como indicador de alarma cuando no se logra."},{"id":147,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K3","pregunta":"¿Cómo se relacionan las medidas de cobertura de redes neuronales con las medidas MC/DC de código tradicional?","opciones":{"a":"Son completamente independientes y no tienen relación","b":"La cobertura signo-signo es similar a MC/DC en código imperativo","c":"La cobertura de neuronas es equivalente a MC/DC","d":"No existen equivalencias entre ambos paradigmas"},"respuesta_correcta":"b","justificacion":"La cobertura signo-signo en redes neuronales es conceptualmente similar a MC/DC (Modified Condition/Decision Coverage) en código imperativo, verificando cómo cambios en una neurona afectan a la siguiente."},{"id":148,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K3","pregunta":"¿Cuál es el impacto de la especificación vaga como requisito 'tan bueno como humano' en la estrategia de pruebas?","opciones":{"a":"Simplifica las pruebas al no requerir métricas precisas","b":"Hace que el problema del oráculo sea más manejable","c":"Crea desafíos en la definición de criterios de aceptación precisos y medibles","d":"No tiene impacto en la estrategia de pruebas"},"respuesta_correcta":"c","justificacion":"Los requisitos vagos como 'tan bueno como humano' crean desafíos significativos para definir criterios de aceptación precisos y medibles, agravando el problema del oráculo en sistemas IA."},{"id":149,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K3","pregunta":"¿Cómo deben diferenciarse las pruebas entre un componente IA y un componente no-IA en pruebas de integración?","opciones":{"a":"No hay diferencia en las pruebas de integración","b":"Los componentes IA no requieren pruebas de integración","c":"Las pruebas deben verificar tanto la integración técnica como el comportamiento del modelo IA con datos reales","d":"Solo se prueban los componentes no-IA"},"respuesta_correcta":"c","justificacion":"En pruebas de integración de componentes IA y no-IA, es crucial verificar tanto la integración técnica como el comportamiento del modelo IA cuando interactúa con datos y componentes reales."},{"id":150,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K3","pregunta":"¿Qué riesgos específicos presenta la reutilización de implementaciones de científicos de datos por parte de testers?","opciones":{"a":"Mejora la calidad de las pruebas","b":"Puede ocultar defectos porque los testers copian lógica que ya contiene errores","c":"No presenta riesgos","d":"Acelera el tiempo de prueba sin comprometer la calidad"},"respuesta_correcta":"b","justificacion":"Cuando los testers reutilizan implementaciones de científicos de datos, existe el riesgo de que también reutilicen los errores ya presentes, ocultando defectos en lugar de detectarlos."},{"id":151,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K3","pregunta":"¿Cómo afecta la evaluación exploradora en EDA a las pruebas posteriores?","opciones":{"a":"No tiene relación con las pruebas posteriores","b":"Identifica características de los datos que permiten diseñar pruebas más efectivas y detectar anomalías","c":"Solo se utiliza para documentación","d":"Aumenta innecesariamente el tiempo de prueba"},"respuesta_correcta":"b","justificacion":"El análisis exploratorio de datos (EDA) en las pruebas de entrada identifica características, patrones y anomalías en los datos que informan el diseño de pruebas posteriores más efectivas."},{"id":152,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K3","pregunta":"¿Cuál es la interacción entre las características de calidad IA (como transparencia y explicabilidad) y la testabilidad?","opciones":{"a":"Son completamente independientes","b":"Mayor transparencia facilita la testabilidad al permitir verificar el comportamiento interno","c":"La explicabilidad reduce la necesidad de pruebas","d":"No afectan la testabilidad del sistema"},"respuesta_correcta":"b","justificacion":"Mayor transparencia y explicabilidad en sistemas IA facilitan la testabilidad al permitir que los testers verifiquen y entiendan el comportamiento interno, reduciendo el problema del oráculo."},{"id":153,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K3","pregunta":"¿Cómo se relaciona la calidad de los datos de entrenamiento con los defectos en sistemas IA?","opciones":{"a":"Los defectos de datos no afectan el modelo final","b":"Defectos en datos de entrenamiento pueden causar defectos en el modelo que son difíciles de detectar con pruebas tradicionales","c":"Solo afecta el tiempo de entrenamiento","d":"Los datos no tienen relación con defectos"},"respuesta_correcta":"b","justificacion":"Los defectos en los datos de entrenamiento se propagan al modelo entrenado, causando defectos que son particularmente difíciles de detectar con pruebas tradicionales porque son inherentes al modelo aprendido."},{"id":154,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K3","pregunta":"¿Cuáles son los desafíos principales al establecer criterios no funcionales para sistemas IA?","opciones":{"a":"Los criterios son siempre objetivos y medibles","b":"Complejidad en definir tolerancias precisas, velocidad esperada, consumo de recursos, y adaptabilidad a cambios","c":"No hay desafíos especiales","d":"Solo se relacionan con la velocidad de ejecución"},"respuesta_correcta":"b","justificacion":"Los criterios no funcionales en sistemas IA presentan desafíos en definir tolerancias precisas, velocidad esperada, consumo de recursos, escalabilidad, y capacidad de adaptación a cambios en el entorno."},{"id":155,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K4","pregunta":"¿Cómo podría aplicarse un enfoque de pruebas de niveles múltiples para mitigar tanto el problema del oráculo como el sesgo de automatización?","opciones":{"a":"Los dos problemas son independientes y no pueden ser mitigados conjuntamente","b":"Usar pruebas en múltiples niveles (datos, modelo, componentes, integración, sistema) combinado con supervisión humana en cada nivel para validar resultados","c":"Solo utilizar pruebas de caja negra elimina ambos problemas","d":"Aumentar el número de casos de prueba siempre resuelve ambos problemas"},"respuesta_correcta":"b","justificacion":"Un enfoque de múltiples niveles de prueba combinado con supervisión humana activa en cada nivel puede mitigar tanto el problema del oráculo (mediante validación en diferentes capas) como el sesgo de automatización (mediante vigilancia explícita)."},{"id":156,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K4","pregunta":"¿Cuál es la estrategia óptima para balancear la cobertura de neuronas con medidas de cobertura más estrictas en un proyecto con recursos limitados?","opciones":{"a":"Usar solo cobertura de neuronas por ser la más fácil de alcanzar","b":"Usar un enfoque escalonado: iniciar con cobertura de neuronas como línea base, luego incrementalmente agregar medidas más estrictas (umbral, sign-change) basadas en riesgo","c":"Aplicar todas las medidas simultáneamente","d":"Ignorar las medidas de cobertura por ser muy costosas"},"respuesta_correcta":"b","justificacion":"Un enfoque escalonado y basado en riesgo permite optimizar recursos: comenzar con cobertura de neuronas como alarma, luego aumentar gradualmente el rigor con medidas más estrictas según criticidad y riesgo del sistema."},{"id":157,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K4","pregunta":"¿Cómo podría integrarse la mitigación de deriva de concepto con una estrategia de pruebas continuas en producción?","opciones":{"a":"Las pruebas en producción y la deriva de concepto son problemas separados","b":"Implementar monitoreo continuo de desempeño del modelo, pruebas A/B periódicas, re-entrenamiento automático, y regresión para detectar degradación antes de que afecte usuarios","c":"Esperar a que el desempeño degradado sea reportado por usuarios","d":"No se puede hacer nada sobre la deriva de concepto después del despliegue"},"respuesta_correcta":"b","justificacion":"Una estrategia integrada incluye: monitoreo continuo de métricas de desempeño, pruebas A/B periódicas para validar nuevas versiones, re-entrenamiento automático cuando se detecta degradación, y pruebas de regresión continuas."},{"id":158,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K4","pregunta":"¿Cuál sería el impacto de no documentar adecuadamente los conjuntos de datos utilizados en sistemas IA en términos de mantenimiento y reutilización?","opciones":{"a":"No tiene impacto, cualquiera puede reutilizar el modelo","b":"Impide comprender cambios en desempeño, sesgo no detectado, imposibilidad de reproducir resultados, riesgo de RGPD, y dependencia de personas específicas","c":"Solo afecta la velocidad de carga","d":"Mejora la privacidad del sistema"},"respuesta_correcta":"b","justificacion":"La falta de documentación de conjuntos de datos causa: dificultad para entender cambios de desempeño, sesgo oculto, irreproducibilidad, riesgos de cumplimiento (RGPD), y conocimiento dependiente de individuos clave."},{"id":159,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K4","pregunta":"¿Cómo debería diseñarse una estrategia de pruebas de datos que aborde simultáneamente problemas de calidad de datos, privacidad (RGPD) y equivalencia de canalizaciones?","opciones":{"a":"Estos son tres problemas separados que no pueden abordarse conjuntamente","b":"Combinar EDA para calidad, anonimización y encriptación para RGPD, y validación de equivalencia funcional entre canalización de entrenamiento y operativa","c":"Ignorar privacidad para enfocarse en calidad","d":"Usar una única prueba para todos los aspectos"},"respuesta_correcta":"b","justificacion":"Una estrategia integral debe incluir: análisis exploratorio de datos para detectar problemas de calidad, implementación de controles de privacidad (anonimización, cifrado) para RGPD, y validación explícita de equivalencia funcional entre canalizaciones."},{"id":160,"modulo":"Módulo 4: Redes Neuronales, Pruebas de Sistemas y Calidad IA","nivel":"K4","pregunta":"¿Cómo se relacionan la transparencia, explicabilidad e interpretabilidad en el contexto de una estrategia de pruebas integral para sistemas IA?","opciones":{"a":"Son términos sinónimos, la distinción es innecesaria","b":"Transparencia facilita auditoría (documentación vs implementación), explicabilidad permite entender decisiones (LIME, perturbaciones), interpretabilidad depende del usuario y requiere feedback","c":"Solo importa la transparencia para las pruebas","d":"Estas características no afectan las pruebas"},"respuesta_correcta":"b","justificacion":"En pruebas integrales: transparencia permite verificar documentación vs implementación, explicabilidad (mediante LIME, perturbaciones) ayuda a entender decisiones del modelo, e interpretabilidad (específica del usuario) requiere validación mediante encuestas y feedback."},{"id":161,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K1","pregunta":"¿Qué es un ataque adversario en sistemas basados en IA?","opciones":{"a":"Una modificación del código fuente para introducir defectos","b":"Una perturbación sutil en entradas válidas para causar predicciones incorrectas","c":"Un acceso no autorizado a la base de datos de entrenamiento","d":"Una acción que reduce el rendimiento del hardware del sistema"},"respuesta_correcta":"b","justificacion":"Un ataque adversario es una perturbación mínima en entradas válidas diseñada para provocar predicciones erróneas en el modelo de IA sin ser detectada por el ojo humano."},{"id":162,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K1","pregunta":"¿Cuál es la característica principal de los ejemplos adversarios transferibles?","opciones":{"a":"Solo funcionan en el modelo original donde se crearon","b":"Pueden fallar en distintos modelos y arquitecturas diferentes","c":"Requieren cambios visibles en las entradas para ser efectivos","d":"Son específicos de cada tipo de dato (solo imágenes o solo texto)"},"respuesta_correcta":"b","justificacion":"La transferibilidad es una propiedad clave de los ejemplos adversarios: un ejemplo adversario que engaña a un modelo puede engañar a otros modelos diferentes, incluso si fueron entrenados de forma distinta."},{"id":163,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K1","pregunta":"¿Qué diferencia principal existe entre ataques de caja blanca y caja negra?","opciones":{"a":"Los ataques de caja blanca son más lentos que los de caja negra","b":"En caja blanca el atacante conoce el algoritmo y parámetros; en caja negra no","c":"Los ataques de caja negra solo funcionan en modelos lineales","d":"La caja blanca requiere acceso a internet mientras caja negra no"},"respuesta_correcta":"b","justificacion":"En un ataque de caja blanca, el atacante tiene conocimiento completo del algoritmo y sus parámetros. En un ataque de caja negra, el atacante debe explorar y construir un duplicado del sistema antes de aplicar técnicas de caja blanca."},{"id":164,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K1","pregunta":"¿Qué es el envenenamiento de datos?","opciones":{"a":"La eliminación accidental de datos de entrenamiento","b":"La manipulación intencional de datos de entrenamiento para afectar el modelo","c":"El almacenamiento de datos en servidores inseguros","d":"La compresión excesiva de datos para reducir espacio"},"respuesta_correcta":"b","justificacion":"El envenenamiento de datos es la manipulación deliberada de datos de entrenamiento para degradar el rendimiento del modelo o causar comportamientos específicos indeseados."},{"id":165,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K1","pregunta":"¿Cuáles son los dos tipos principales de envenenamiento de datos?","opciones":{"a":"Estructurado e inestructurado","b":"Aleatorio y sistemático","c":"Dirigido e indiscriminado","d":"Local y remoto"},"respuesta_correcta":"c","justificacion":"El envenenamiento dirigido intenta causar misclasificaciones específicas, mientras que el envenenamiento indiscriminado busca degradar el rendimiento general del modelo (tipo Denegación de Servicio)."},{"id":166,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"En el contexto de ataques adversarios, ¿por qué es importante la propiedad de transferibilidad para los testers?","opciones":{"a":"Porque permite usar solo un modelo para probar todos los sistemas","b":"Porque indica que ejemplos adversarios encontrados en un modelo pueden revelar vulnerabilidades en otros","c":"Porque reduce el tiempo total de las pruebas sin afectar cobertura","d":"Porque evita la necesidad de crear ejemplos adversarios nuevos"},"respuesta_correcta":"b","justificacion":"La transferibilidad es importante porque un ejemplo adversario que funciona contra un modelo puede funcionar contra otros modelos diferentes. Esto significa que los testers pueden identificar vulnerabilidades que afectarían a múltiples versiones o variantes del sistema."},{"id":167,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Cuál es el propósito principal de las pruebas adversarias en sistemas de IA?","opciones":{"a":"Entrenar el modelo para ser más rápido","b":"Ejecutar ataques adversarios para identificar vulnerabilidades y fortalecer el modelo","c":"Reducir el costo computacional del entrenamiento","d":"Simplificar la arquitectura del modelo neuronal"},"respuesta_correcta":"b","justificacion":"Las pruebas adversarias consisten en ejecutar ataques adversarios intencionalmente para descubrir vulnerabilidades. Los ejemplos adversarios encontrados se añaden al conjunto de entrenamiento para mejorar la robustez del modelo."},{"id":168,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"Dado un escenario donde se sospecha envenenamiento de datos en un modelo de clasificación de spam. ¿Cuál es el primer paso recomendado para detectarlo?","opciones":{"a":"Reentrenar completamente el modelo desde cero","b":"Realizar un análisis exploratorio de datos (EDA) buscando patrones atípicos","c":"Crear versiones clónicas del modelo inmediatamente","d":"Eliminar aleatoriamente el 50% de los datos"},"respuesta_correcta":"b","justificacion":"El análisis exploratorio de datos (EDA) es el primer paso para detectar envenenamiento, buscando datos atípicos, patrones inusuales y anomalías que indiquen manipulación intencional."},{"id":169,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Por qué es importante revisar la procedencia y las políticas de adquisición de datos?","opciones":{"a":"Para cumplir con regulaciones de privacidad únicamente","b":"Para identificar fuentes de riesgo de envenenamiento y validar la calidad de los datos","c":"Para aumentar el tamaño del conjunto de entrenamiento","d":"Para mejorar la velocidad del modelo"},"respuesta_correcta":"b","justificacion":"Revisar la procedencia y políticas de adquisición ayuda a identificar puntos vulnerables donde los datos podrían haber sido manipulados, y es parte de la mitigación del riesgo de envenenamiento."},{"id":170,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"En un ataque de caja negra contra un sistema de IA, ¿cuál es el paso fundamental que realiza el atacante antes de ejecutar un ataque tipo caja blanca?","opciones":{"a":"Obtener acceso físico al servidor","b":"Construir un modelo duplicado del sistema original","c":"Modificar directamente el código fuente","d":"Inyectar malware en la infraestructura"},"respuesta_correcta":"b","justificacion":"En un ataque de caja negra, el atacante explora el sistema, aprende su comportamiento, y construye un duplicado. Una vez tiene este duplicado, puede aplicar técnicas de caja blanca (con conocimiento del algoritmo) y luego transferir los ataques al sistema original."},{"id":171,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K3","pregunta":"Un equipo de testing descubre que cambiar solo 3 píxeles en una imagen causa que un clasificador de dígitos manuscritos prediga incorrectamente. ¿Qué concepto de testing describe mejor esta situación?","opciones":{"a":"Prueba de regresión","b":"Ejemplo adversario con transferibilidad","c":"Envenenamiento de datos indiscriminado","d":"Prueba de carga del sistema"},"respuesta_correcta":"b","justificacion":"Este es un ejemplo clásico de un ejemplo adversario: una perturbación mínima e imperceptible al humano (3 píxeles) que causa una predicción incorrecta. Esta vulnerabilidad podría ser transferible a otros clasificadores similares."},{"id":172,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K3","pregunta":"Un sistema de IA de filtrado de correo spam detecta un aumento inusual en mensajes clasificados como 'legítimos' cuando históricamente lo hacía correctamente. Se sospecha envenenamiento dirigido. ¿Cuál sería la estrategia de mitigación más apropiada?","opciones":{"a":"Pausar el sistema indefinidamente sin investigar","b":"Realizar pruebas A/B comparando la versión actual con versiones anteriores y usar regresión automatizada","c":"Entrenar un modelo completamente nuevo sin revisar datos","d":"Aumentar arbitrariamente la tasa de filtrado de todos los mensajes"},"respuesta_correcta":"b","justificacion":"Las pruebas A/B permiten comparar la variante envenenada contra versiones anteriores conocidas como correctas, y la regresión automatizada puede detectar qué cambios causaron el problema. Esto es la estrategia recomendada para mitigar envenenamiento."},{"id":173,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K3","pregunta":"En una arquitectura de sistema con múltiples modelos de IA (ensemble), ¿por qué usar pseudo-oráculos individuales para cada modelo es insuficiente para garantizar calidad?","opciones":{"a":"Porque los pseudo-oráculos siempre son más lentos que oráculos reales","b":"Porque los modelos individuales pueden compartir defectos comunes o arquitecturas similares","c":"Porque la automatización es imposible con múltiples modelos","d":"Porque el ensemble nunca mejora el rendimiento individual"},"respuesta_correcta":"b","justificacion":"Aunque cada modelo tenga su pseudo-oráculo, si comparten arquitectura similar o código común, el mismo defecto podría existir en múltiples modelos y no sería detectado. Por eso es importante que los pseudo-oráculos sean realmente distintos."},{"id":174,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K1","pregunta":"¿Qué es el pairwise testing?","opciones":{"a":"Una técnica que prueba solo dos parámetros del sistema","b":"Una técnica combinatoria que prueba todas las interacciones entre pares de parámetros","c":"Un método que requiere oráculos múltiples","d":"Una estrategia de pruebas basadas únicamente en experiencia"},"respuesta_correcta":"b","justificacion":"El pairwise testing es una técnica combinatoria que se enfoca en probar las interacciones entre pares de parámetros, reduciendo dramáticamente el número de combinaciones a probar en comparación con todas las combinaciones posibles."},{"id":175,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Por qué es el pairwise testing especialmente relevante en sistemas de IA?","opciones":{"a":"Porque todos los defectos de IA están en parámetros individuales","b":"Porque reduce costos de hardware de entrenamiento","c":"Porque los sistemas IA tienen muchos parámetros y generan combinaciones casi infinitas, mientras que la mayoría de defectos provienen de interacciones de pocos parámetros","d":"Porque elimina la necesidad de validación en producción"},"respuesta_correcta":"c","justificacion":"El pairwise testing es ideal para IA porque: (1) hay muchos parámetros que generan combinaciones infinitas, (2) la investigación muestra que la mayoría de defectos provienen de interacciones entre pocos parámetros, (3) permite cubrir casos críticos con menos esfuerzo."},{"id":176,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"Un modelo de IA tiene 6 parámetros hiperparametrizables con 3 valores posibles cada uno. ¿Cuántas combinaciones teóricas existen sin pairwise testing?","opciones":{"a":"18 combinaciones","b":"36 combinaciones","c":"729 combinaciones","d":"2.187 combinaciones"},"respuesta_correcta":"c","justificacion":"Con 6 parámetros y 3 valores cada uno: 3^6 = 729 combinaciones teóricas. El pairwise testing reduciría esto significativamente enfocándose solo en las interacciones de pares."},{"id":177,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Qué requisitos previos son necesarios para implementar efectivamente pairwise testing en pruebas de sistemas IA?","opciones":{"a":"Solo documentación del modelo y acceso a código fuente","b":"Automatización de pruebas y entornos virtuales de prueba","c":"Equipos de testing en múltiples ubicaciones geográficas","d":"Uso obligatorio de frameworks específicos de IA"},"respuesta_correcta":"b","justificacion":"El pairwise testing efectivo requiere: (1) herramientas de generación de casos de prueba pairwise, (2) automatización para ejecutar los casos de forma eficiente, (3) entornos virtuales de prueba para aislar el sistema durante las pruebas."},{"id":178,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K1","pregunta":"¿Cuál es el propósito principal de las pruebas back-to-back?","opciones":{"a":"Automatizar todas las pruebas de regresión","b":"Comparar resultados del sistema bajo prueba con un pseudo-oráculo para resolver el problema del oráculo","c":"Probar el sistema en ambientes de desarrollo y producción simultáneamente","d":"Revertir cambios en el código automáticamente si hay fallos"},"respuesta_correcta":"b","justificacion":"Las pruebas back-to-back solucionan el problema del oráculo usando un pseudo-oráculo: otra implementación, versión, plataforma o algoritmo que actúa como referencia para validar los resultados del sistema bajo prueba."},{"id":179,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"En una prueba back-to-back entre dos sistemas de IA, ¿qué característica es CRÍTICA para que el pseudo-oráculo sea efectivo?","opciones":{"a":"Debe tener exactamente el mismo rendimiento no funcional que el SUT","b":"Debe ser más rápido que el SUT","c":"NO debe compartir software común que pudiera enmascarar defectos iguales en ambos","d":"Debe usar la misma arquitectura neuronal que el SUT"},"respuesta_correcta":"c","justificacion":"La característica crítica es la INDEPENDENCIA: el pseudo-oráculo no debe compartir software común con el SUT, porque si ambos tienen el mismo defecto (por usar el mismo código), este no sería detectado. Pueden diferir en rendimiento, arquitectura, pero deben ser independientes en su implementación."},{"id":180,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Cuál es el principal desafío al seleccionar un pseudo-oráculo adecuado para pruebas back-to-back?","opciones":{"a":"Siempre son más costosos que oráculos reales","b":"El código abierto inmaduro y pobre documentación dificultan verificar si comparten software común","c":"No pueden usarse con redes neuronales","d":"Requieren siempre entrenamiento adicional"},"respuesta_correcta":"b","justificacion":"El desafío principal es que código abierto inmaduro, documentación incompleta y falta de trazabilidad hacen difícil detectar si el pseudo-oráculo y el SUT comparten software común subyacente, lo que podría enmascarar defectos."},{"id":181,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K3","pregunta":"Se debe probar un sistema de reconocimiento facial basado en deep learning. Se decide usar back-to-back comparando contra una alternativa implementada en SVM (máquinas de soporte vectorial). ¿Cuál sería una preocupación válida?","opciones":{"a":"Los SVMs siempre son más precisos que deep learning","b":"Las dos arquitecturas son completamente independientes, lo que garantiza detección de todos los defectos","c":"Ambas técnicas podrían compartir defectos en la extracción de características de las imágenes de entrada","d":"Es imposible comparar deep learning con SVM"},"respuesta_correcta":"c","justificacion":"Aunque deep learning y SVM sean arquitecturas distintas, podrían compartir problemas en etapas previas (extracción de características, normalización de imágenes). Si este código es común, defectos en esta etapa no serían detectados por back-to-back."},{"id":182,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K1","pregunta":"¿Cuál es la diferencia clave entre pruebas A/B y pruebas back-to-back?","opciones":{"a":"A/B compara dos variantes del MISMO sistema; back-to-back detecta DEFECTOS en sistemas distintos","b":"Back-to-back solo funciona con redes neuronales","c":"A/B requiere automatización completa mientras back-to-back no","d":"No hay diferencia técnica, son sinónimos"},"respuesta_correcta":"a","justificacion":"La diferencia fundamental: A/B compara dos variantes (versiones) del MISMO sistema con el mismo algoritmo; back-to-back compara SISTEMAS DISTINTOS para detectar defectos. A/B usa un enfoque estadístico, back-to-back busca vulnerabilidades comparativas."},{"id":183,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Por qué las pruebas A/B requieren un enfoque estadístico en lugar de determinista?","opciones":{"a":"Porque los sistemas IA siempre tienen resultados aleatorios","b":"Porque comparan dos variantes del mismo sistema con las mismas entradas, y necesitan múltiples ensayos para validar si las diferencias son significativas","c":"Porque evita la necesidad de oráculos","d":"Porque es más rápido que otros métodos"},"respuesta_correcta":"b","justificacion":"Las pruebas A/B necesitan un enfoque estadístico porque: (1) ejecutan las mismas entradas en ambas variantes, (2) comparan resultados para encontrar diferencias significativas, (3) requieren múltiples ensayos para establecer significancia estadística, no una comparación única."},{"id":184,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"En un sistema de IA auto-aprendiente, ¿cómo se aplican las pruebas A/B para validación?","opciones":{"a":"Se comparan dos versiones del modelo con datos históricos; si la nueva versión mejora se acepta, si no se revierte","b":"Se prueban todas las posibles configuraciones de parámetros","c":"Se elimina la versión anterior automáticamente","d":"Se requiere aprobación manual de cada resultado"},"respuesta_correcta":"a","justificacion":"En sistemas auto-aprendientes, A/B permite: (1) comparar versión nueva vs. anterior del modelo, (2) validar contra criterios de aceptación predefinidos, (3) aceptar la mejora o revertir a la versión anterior en base a resultados estadísticos."},{"id":185,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Cuál es el rol del sistema existente en las pruebas A/B?","opciones":{"a":"Actúa como oráculo COMPLETO, generando casos y guiando el diseño de pruebas","b":"Actúa como oráculo PARCIAL, permitiendo comparación pero sin generar casos ni guiar diseño","c":"No tiene ningún rol","d":"Debe ser eliminado antes de las pruebas"},"respuesta_correcta":"b","justificacion":"El sistema existente en A/B actúa como oráculo parcial: permite validar contra criterios de aceptación comparando dos variantes, pero no genera casos de prueba ni guía el diseño de pruebas como lo haría un oráculo completo."},{"id":186,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K1","pregunta":"¿Qué es una prueba metamórfica (PM)?","opciones":{"a":"Una prueba que transforma el código fuente del sistema","b":"Genera casos de seguimiento transformando un caso fuente según una relación metamórfica","c":"Una técnica que requiere metamodelos formales","d":"Un método que prueba cambios en la estructura de datos"},"respuesta_correcta":"b","justificacion":"Una prueba metamórfica toma un caso fuente y lo transforma usando una relación metamórfica (RM) que describe cómo los cambios en las entradas deberían reflejarse en los resultados, para generar casos de seguimiento y verificar la relación entre resultados."},{"id":187,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Cuál es el beneficio principal de las pruebas metamórficas cuando existe el problema del oráculo?","opciones":{"a":"Permite probar sin generar resultados esperados absolutos, verificando relaciones entre resultados","b":"Elimina completamente la necesidad de pruebas","c":"Garantiza que no habrá defectos","d":"Reduce el tiempo de ejecución a cero"},"respuesta_correcta":"a","justificacion":"El beneficio principal es que PM permite verificar RELACIONES entre resultados sin necesidad de generar valores esperados absolutos. Incluso sin oráculos tradicionales, se puede verificar que los resultados se relacionen correctamente entre sí."},{"id":188,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"En una prueba metamórfica de un sistema de cálculo de promedio, ¿cuál sería una relación metamórfica válida?","opciones":{"a":"Si reordeno los números, el promedio debería cambiar","b":"Si multiplico todos los números por 2, el promedio debería multiplicarse por 2","c":"Si agrego números negativos, el promedio siempre disminuye","d":"El promedio siempre debe ser igual al primer número"},"respuesta_correcta":"b","justificacion":"Esta es una relación metamórfica válida: si todas las entradas se multiplican por una constante k, el promedio debería multiplicarse por la misma constante. Permite verificar la relación sin necesidad de un oráculo para el resultado absoluto."},{"id":189,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿En qué situaciones las pruebas metamórficas son especialmente útiles?","opciones":{"a":"Solo en pruebas de rendimiento","b":"En big data, IA, sistemas sin oráculo y donde generar resultados esperados es problemático","c":"Únicamente para validar interfaces de usuario","d":"Solo en sistemas de tiempo real"},"respuesta_correcta":"b","justificacion":"Las PM son especialmente útiles en: (1) big data donde generar oráculos es difícil, (2) sistemas IA sin oráculo claro, (3) reconocimiento de imágenes, (4) buscadores, (5) optimización de rutas, (6) sistemas de voz. Son aplicables tanto a pruebas funcionales como no funcionales."},{"id":190,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K3","pregunta":"Un sistema de IA para reconocimiento de objetos en imágenes no tiene oráculo definido para validar resultados absolutos. ¿Cómo podrían aplicarse pruebas metamórficas?","opciones":{"a":"No pueden aplicarse porque no hay oráculo","b":"Aplicando relaciones como: si roto la imagen 90 grados, los objetos detectados deberían ser los mismos; si oscurezco la imagen, el modelo debería tener menor confianza","c":"Solo aumentando el tamaño del conjunto de entrenamiento","d":"Usando exclusively técnicas de caja negra"},"respuesta_correcta":"b","justificacion":"Las PM pueden aplicarse definiendo relaciones metamórficas válidas: (1) rotación de 90 grados → objetos detectados iguales, (2) cambios de iluminación → confianza afectada de forma predecible, (3) escalado de imagen → relación de proporciones conservada. Sin oráculo absoluto, verificamos relaciones."},{"id":191,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Cuántas relaciones metamórficas (RMs) diversas se necesitan para revelar un porcentaje alto de defectos?","opciones":{"a":"Solo 1 RM es suficiente","b":"Entre 3-6 RMs diversas pueden revelar más del 90% de defectos detectables","c":"Se necesitan al menos 50 RMs distintas","d":"Las RMs no tienen correlación con defectos encontrados"},"respuesta_correcta":"b","justificacion":"La investigación muestra que con 3-6 relaciones metamórficas bien diseñadas y diversas, se pueden revelar más del 90% de los defectos que serían detectables con oráculos tradicionales. Esto hace PM una técnica muy eficiente."},{"id":192,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K3","pregunta":"Un tester descubre que un caso fuente en una prueba metamórfica produce resultados incorrectos. ¿Puede aún utilizar pruebas metamórficas de forma efectiva?","opciones":{"a":"No, porque el caso fuente debe ser correcto siempre","b":"Sí, porque PM verifica RELACIONES entre resultados. Incluso si el caso fuente es incorrecto, la relación metamórfica puede revelar inconsistencias","c":"Solo si reemplaza el caso fuente con otro","d":"Debe detener las pruebas inmediatamente"},"respuesta_correcta":"b","justificacion":"Una ventaja clave de PM es que incluso si el caso fuente no es 100% correcto, la relación metamórfica permite verificar que los resultados SE RELACIONAN consistentemente. Esto revela inconsistencias y defectos que violarían la relación esperada."},{"id":193,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Por qué Google utiliza GraphicsFuzz en sus pruebas automatizadas?","opciones":{"a":"Para mejorar la velocidad de los shaders gráficos","b":"Para aplicar pruebas metamórficas automatizadas en sistemas gráficos","c":"Para eliminar la necesidad de testers","d":"Para compilar código más rápidamente"},"respuesta_correcta":"b","justificacion":"Google aplica PM automatizada con GraphicsFuzz en pruebas gráficas. GraphicsFuzz transforma programas gráficos (shaders) mediante mutaciones, aplica RMs para verificar que el sistema se comporta correctamente bajo transformaciones, detectando defectos sin oráculos explícitos."},{"id":194,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K1","pregunta":"¿Qué es la adivinación de errores en pruebas basadas en experiencia?","opciones":{"a":"Adivinar aleatoriamente qué código contiene defectos","b":"Usar el conocimiento del tester y fallos previos en sistemas similares para anticipar defectos","c":"Un método que requiere oráculo formal","d":"Generar casos de prueba únicamente de forma aleatoria"},"respuesta_correcta":"b","justificacion":"La adivinación de errores combina: (1) conocimiento del tester sobre sistemas similares, (2) fallos históricos encontrados previamente, (3) en el contexto de IA: conocimiento sobre sesgos sistémicos en datos. Permite anticipar dónde se encuentran típicamente defectos."},{"id":195,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Cuál es el objetivo principal de las pruebas exploratorias en sistemas de IA?","opciones":{"a":"Automatizar completamente todas las pruebas","b":"Diseñar-ejecutar-aprender iterativamente, especialmente útil cuando especificaciones son pobres o el problema del oráculo existe","c":"Eliminar la necesidad de casos de prueba documentados","d":"Reducir costos eliminando testers"},"respuesta_correcta":"b","justificacion":"Las pruebas exploratorias siguen un ciclo iterativo: diseñar → ejecutar → aprender → diseñar nuevas pruebas. Son especialmente valiosas cuando: (1) especificaciones son pobres, (2) existe problema de oráculo, (3) se deben complementar con PM para máxima cobertura."},{"id":196,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Qué son los 'tours' en el contexto de pruebas basadas en experiencia?","opciones":{"a":"Visitas físicas a las instalaciones de desarrollo","b":"Metáforas para estrategias/objetivos con foco concreto en las pruebas","c":"Guías turísticas para usuarios finales","d":"Documentación de requisitos formales"},"respuesta_correcta":"b","justificacion":"Los 'tours' son estrategias de prueba con un objetivo específico. Tours típicos en IA incluyen: (1) tour de sesgo - buscar sesgos sistémicos, (2) tour de subajuste - verificar si el modelo aprende bien, (3) tour de sobreajuste - verificar generalización, (4) tour de datos - examinar tipos, distribución, variaciones, rangos."},{"id":197,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Cuál es el enfoque del tour de datos en pruebas de sistemas IA?","opciones":{"a":"Probar solo datos estructurados","b":"Examinar tipos de datos, distribución, variaciones, rangos, y luego probar cómo el modelo maneja estos datos","c":"Eliminar datos atípicos sin investigar","d":"Aceptar cualquier dato que cumpla el tipo esperado"},"respuesta_correcta":"b","justificacion":"El tour de datos es una estrategia que: (1) analiza las características de los datos (tipos, distribución, variaciones, rangos), (2) identifica patrones y atípicos, (3) luego diseña casos de prueba para validar cómo el modelo maneja esta variedad de datos."},{"id":198,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K2","pregunta":"¿Qué es el EDA (Análisis Exploratorio de Datos) y cuál es su valor en pruebas de IA?","opciones":{"a":"Una herramienta exclusiva para almacenamiento de datos","b":"Buscar patrones, relaciones, tendencias y atípicos usando visualización; puede validar algoritmos y encontrar mejoras","c":"Un reemplazo para todas las otras técnicas de prueba","d":"Un método que requiere máquinas virtuales especiales"},"respuesta_correcta":"b","justificacion":"EDA permite: (1) visualizar datos y descubrir patrones, (2) identificar relaciones y tendencias, (3) encontrar atípicos que indiquen envenenamiento, (4) validar si el algoritmo es apropiado para los datos, (5) descubrir oportunidades de mejora. Google usa lista de 28 pruebas ML como checklist complementario."},{"id":199,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K3","pregunta":"Se debe probar un modelo de IA con especificaciones muy vagas y sin oráculo claro. ¿Cuál sería la mejor combinación de técnicas?","opciones":{"a":"Solo pairwise testing","b":"Pruebas exploratorias combinadas con pruebas metamórficas","c":"Solo back-to-back sin otras técnicas","d":"Únicamente pruebas A/B"},"respuesta_correcta":"b","justificacion":"Cuando hay especificaciones pobres y sin oráculo: (1) pruebas exploratorias permiten aprender iterativamente, (2) pruebas metamórficas resuelven el problema del oráculo verificando relaciones. Juntas proporcionan cobertura máxima incluso en condiciones adversas."},{"id":200,"modulo":"Módulo 5: Métodos y Técnicas de Prueba para IA","nivel":"K3","pregunta":"Un equipo descubre que un modelo de clasificación tiene sesgo sistémico contra un grupo demográfico específico. Considerando el riesgo alto del defecto, ¿qué técnicas deberían aplicarse además de las pruebas exploratorias?","opciones":{"a":"Solo aumentar los datos de entrenamiento sin más análisis","b":"Pruebas adversarias (para probar robustez contra manipulación intencional) y EDA (para analizar distribuciones de datos por grupo)","c":"Eliminar el grupo afectado de los datos","d":"Cambiar el modelo sin validar cambios"},"respuesta_correcta":"b","justificacion":"Frente a sesgo con alto impacto: (1) pruebas adversarias verifican si el modelo es robusto a intentos de explotación del sesgo, (2) EDA analiza en detalle cómo el sesgo se distribuye en datos, (3) ambas técnicas son complementarias para una solución integral."}];

/* ─── DESIGN TOKENS ─────────────────────────────────────────────────────── */
const MODULES = [
  { key: "all", label: "Todos", color: "white" },
  { key: "Módulo 1", label: "M1 · Intro IA", color: "indigo" },
  { key: "Módulo 2", label: "M2 · ML", color: "blue" },
  { key: "Módulo 3", label: "M3 · Datos", color: "cyan" },
  { key: "Módulo 4", label: "M4 · Redes/Pruebas", color: "violet" },
  { key: "Módulo 5", label: "M5 · Técnicas", color: "emerald" },
];

const EXAM_MODES = [
  { key: "practice", label: "Práctica libre", desc: "Sin límite de tiempo, con respuestas inmediatas", icon: "📖", questions: null },
  { key: "exam40", label: "Simulacro 40 preguntas", desc: "Como el examen real: 40 preguntas, 60 minutos", icon: "🎯", questions: 40 },
  { key: "exam20", label: "Simulacro rápido", desc: "20 preguntas, 30 minutos", icon: "⚡", questions: 20 },
  { key: "exam10", label: "Mini test", desc: "10 preguntas, 15 minutos", icon: "🔥", questions: 10 },
];

function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function formatTime(seconds) {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m.toString().padStart(2, "0")}:${s.toString().padStart(2, "0")}`;
}

/* ─── MAIN COMPONENT ────────────────────────────────────────────────────── */
export default function SimulacroExamen() {
  const [questions, setQuestions] = useState(ALL_QUESTIONS);
  const [loaded, setLoaded] = useState(ALL_QUESTIONS.length > 10);

  // Load full question set
  useEffect(() => {
    // Questions are already embedded in the component
    if (ALL_QUESTIONS.length > 10) {
      setQuestions(ALL_QUESTIONS);
      setLoaded(true);
    }
  }, []);

  // ─── App state machine ───────────────────────────────────────────────
  const [screen, setScreen] = useState("menu"); // menu | config | exam | results
  const [mode, setMode] = useState(null);
  const [moduleFilter, setModuleFilter] = useState("all");
  const [examQuestions, setExamQuestions] = useState([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState({});
  const [showAnswer, setShowAnswer] = useState(false);
  const [timeLeft, setTimeLeft] = useState(0);
  const [timerActive, setTimerActive] = useState(false);
  const [flagged, setFlagged] = useState(new Set());

  // Timer
  useEffect(() => {
    if (!timerActive || timeLeft <= 0) return;
    const id = setInterval(() => {
      setTimeLeft((t) => {
        if (t <= 1) {
          setTimerActive(false);
          setScreen("results");
          return 0;
        }
        return t - 1;
      });
    }, 1000);
    return () => clearInterval(id);
  }, [timerActive, timeLeft]);

  // Filter questions by module
  const filteredPool = useMemo(() => {
    if (moduleFilter === "all") return questions;
    return questions.filter((q) => q.modulo.startsWith(moduleFilter));
  }, [questions, moduleFilter]);

  // Start exam
  const startExam = useCallback(() => {
    const pool = shuffle(filteredPool);
    const count = mode.questions || pool.length;
    const selected = pool.slice(0, Math.min(count, pool.length));
    setExamQuestions(selected);
    setCurrentIdx(0);
    setAnswers({});
    setShowAnswer(false);
    setFlagged(new Set());
    if (mode.key !== "practice") {
      const minutes = mode.key === "exam40" ? 60 : mode.key === "exam20" ? 30 : 15;
      setTimeLeft(minutes * 60);
      setTimerActive(true);
    } else {
      setTimeLeft(0);
      setTimerActive(false);
    }
    setScreen("exam");
  }, [filteredPool, mode]);

  // Answer question
  const selectAnswer = (qId, option) => {
    if (answers[qId] !== undefined && mode?.key !== "practice") return;
    setAnswers((prev) => ({ ...prev, [qId]: option }));
    if (mode?.key === "practice") setShowAnswer(true);
  };

  // Navigation
  const goTo = (idx) => {
    setCurrentIdx(idx);
    setShowAnswer(false);
  };

  const nextQuestion = () => {
    if (currentIdx < examQuestions.length - 1) {
      goTo(currentIdx + 1);
    }
  };

  const prevQuestion = () => {
    if (currentIdx > 0) {
      goTo(currentIdx - 1);
    }
  };

  const toggleFlag = (qId) => {
    setFlagged((prev) => {
      const s = new Set(prev);
      if (s.has(qId)) s.delete(qId);
      else s.add(qId);
      return s;
    });
  };

  const finishExam = () => {
    setTimerActive(false);
    setScreen("results");
  };

  // Results calculation
  const results = useMemo(() => {
    if (examQuestions.length === 0) return null;
    let correct = 0;
    let wrong = 0;
    let unanswered = 0;
    const byModule = {};
    const byLevel = {};

    examQuestions.forEach((q) => {
      const mod = q.modulo.split(":")[0];
      if (!byModule[mod]) byModule[mod] = { correct: 0, total: 0 };
      if (!byLevel[q.nivel]) byLevel[q.nivel] = { correct: 0, total: 0 };
      byModule[mod].total++;
      byLevel[q.nivel].total++;

      if (answers[q.id] === undefined) {
        unanswered++;
      } else if (answers[q.id] === q.respuesta_correcta) {
        correct++;
        byModule[mod].correct++;
        byLevel[q.nivel].correct++;
      } else {
        wrong++;
      }
    });

    const total = examQuestions.length;
    const score = Math.round((correct / total) * 100);
    const passed = score >= 65;
    return { correct, wrong, unanswered, total, score, passed, byModule, byLevel };
  }, [examQuestions, answers]);

  const currentQ = examQuestions[currentIdx] || null;
  const answeredCount = Object.keys(answers).length;
  const progress = examQuestions.length > 0 ? Math.round((answeredCount / examQuestions.length) * 100) : 0;

  /* ─── SCREENS ─────────────────────────────────────────────────────────── */

  // ── MENU ──
  if (screen === "menu") {
    return (
      <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center p-4">
        <div className="max-w-2xl w-full space-y-8">
          <header className="text-center space-y-3">
            <div className="inline-flex items-center gap-3 bg-white/5 border border-white/10 rounded-2xl px-5 py-3">
              <span className="text-3xl">🧪</span>
              <div className="text-left">
                <h1 className="text-2xl font-black tracking-tight">Simulacro ISTQB CT-AI</h1>
                <p className="text-gray-400 text-sm">{questions.length} preguntas · 5 módulos · Niveles K1-K4</p>
              </div>
            </div>
          </header>

          <section className="space-y-3" aria-label="Modos de examen">
            <h2 className="text-sm font-semibold text-gray-500 uppercase tracking-widest px-1">Elige un modo</h2>
            {EXAM_MODES.map((m) => (
              <button
                key={m.key}
                onClick={() => { setMode(m); setScreen("config"); }}
                className="w-full text-left bg-white/5 hover:bg-white/10 border border-white/10 hover:border-white/20 rounded-xl p-5 transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 group"
                aria-label={`${m.label}: ${m.desc}`}
              >
                <div className="flex items-center gap-4">
                  <span className="text-3xl group-hover:scale-110 transition-transform duration-200">{m.icon}</span>
                  <div className="flex-1 min-w-0">
                    <p className="font-bold text-lg text-white">{m.label}</p>
                    <p className="text-gray-400 text-sm">{m.desc}</p>
                  </div>
                  <svg className="w-5 h-5 text-gray-500 group-hover:text-white transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                </div>
              </button>
            ))}
          </section>

          <p className="text-center text-gray-600 text-xs">Nota de aprobación: 65% · El examen real tiene 40 preguntas en 60 minutos</p>
        </div>
      </div>
    );
  }

  // ── CONFIG ──
  if (screen === "config") {
    const poolSize = filteredPool.length;
    const examSize = mode.questions ? Math.min(mode.questions, poolSize) : poolSize;

    return (
      <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center p-4">
        <div className="max-w-xl w-full space-y-6">
          <button onClick={() => setScreen("menu")} className="text-gray-400 hover:text-white text-sm flex items-center gap-1 transition-colors focus:outline-none focus:ring-2 focus:ring-white/30 rounded">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
            Volver
          </button>

          <header className="space-y-1">
            <h1 className="text-2xl font-black flex items-center gap-3">{mode.icon} {mode.label}</h1>
            <p className="text-gray-400">{mode.desc}</p>
          </header>

          <section className="space-y-3" aria-label="Filtro por módulo">
            <h2 className="text-sm font-semibold text-gray-500 uppercase tracking-widest">Filtrar por módulo</h2>
            <div className="grid grid-cols-2 gap-2">
              {MODULES.map((m) => {
                const count = m.key === "all" ? questions.length : questions.filter(q => q.modulo.startsWith(m.key)).length;
                return (
                  <button
                    key={m.key}
                    onClick={() => setModuleFilter(m.key)}
                    className={`p-3 rounded-xl text-left text-sm font-medium transition-all duration-200 border focus:outline-none focus:ring-2 focus:ring-indigo-500 ${
                      moduleFilter === m.key
                        ? "bg-indigo-600/20 border-indigo-500/50 text-white"
                        : "bg-white/5 border-white/10 text-gray-300 hover:bg-white/10"
                    }`}
                    aria-pressed={moduleFilter === m.key}
                  >
                    <span className="block font-bold">{m.label}</span>
                    <span className="text-xs text-gray-400">{count} preguntas</span>
                  </button>
                );
              })}
            </div>
          </section>

          <div className="bg-white/5 border border-white/10 rounded-xl p-4 space-y-2">
            <div className="flex justify-between text-sm">
              <span className="text-gray-400">Preguntas disponibles</span>
              <span className="font-bold">{poolSize}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-gray-400">Se tomarán</span>
              <span className="font-bold text-indigo-400">{examSize} (aleatorias)</span>
            </div>
            {mode.key !== "practice" && (
              <div className="flex justify-between text-sm">
                <span className="text-gray-400">Tiempo</span>
                <span className="font-bold text-amber-400">{mode.key === "exam40" ? "60" : mode.key === "exam20" ? "30" : "15"} min</span>
              </div>
            )}
          </div>

          <button
            onClick={startExam}
            disabled={poolSize === 0}
            className="w-full py-4 rounded-xl bg-indigo-600 hover:bg-indigo-500 font-bold text-lg transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-indigo-400 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Comenzar
          </button>
        </div>
      </div>
    );
  }

  // ── EXAM ──
  if (screen === "exam" && currentQ) {
    const userAnswer = answers[currentQ.id];
    const isAnswered = userAnswer !== undefined;
    const isCorrect = userAnswer === currentQ.respuesta_correcta;
    const isPractice = mode?.key === "practice";
    const showFeedback = isPractice && showAnswer && isAnswered;
    const isFlagged = flagged.has(currentQ.id);
    const timeWarning = timerActive && timeLeft < 300;

    return (
      <div className="min-h-screen bg-gray-950 text-white">
        {/* Top Bar */}
        <header className="sticky top-0 z-20 bg-gray-950/95 backdrop-blur-sm border-b border-white/10 px-4 py-3">
          <div className="max-w-3xl mx-auto">
            <div className="flex items-center justify-between gap-3">
              <div className="flex items-center gap-2 min-w-0">
                <span className="text-sm font-bold text-gray-400 shrink-0">{currentIdx + 1}/{examQuestions.length}</span>
                <div className="h-1.5 flex-1 bg-white/10 rounded-full overflow-hidden min-w-16">
                  <div className="h-full bg-indigo-500 rounded-full transition-all duration-300" style={{ width: `${progress}%` }} />
                </div>
                <span className="text-xs text-gray-500 shrink-0">{progress}%</span>
              </div>
              {timerActive && (
                <div className={`font-mono text-lg font-bold tabular-nums shrink-0 ${timeWarning ? "text-red-400 animate-pulse" : "text-amber-400"}`} aria-live="polite" aria-label={`Tiempo restante: ${formatTime(timeLeft)}`}>
                  {formatTime(timeLeft)}
                </div>
              )}
              {!isPractice && (
                <button onClick={finishExam} className="px-3 py-1.5 text-xs font-semibold bg-red-500/20 text-red-300 hover:bg-red-500/30 rounded-lg transition-colors focus:outline-none focus:ring-2 focus:ring-red-400">
                  Terminar
                </button>
              )}
              {isPractice && (
                <button onClick={() => setScreen("menu")} className="px-3 py-1.5 text-xs font-semibold bg-white/10 text-gray-300 hover:bg-white/20 rounded-lg transition-colors focus:outline-none focus:ring-2 focus:ring-white/30">
                  Salir
                </button>
              )}
            </div>
          </div>
        </header>

        {/* Question */}
        <main className="max-w-3xl mx-auto px-4 py-6 space-y-5">
          {/* Tags */}
          <div className="flex items-center gap-2 flex-wrap">
            <span className="px-2.5 py-1 rounded-full text-xs font-bold bg-indigo-600/30 text-indigo-300 border border-indigo-500/30">
              {currentQ.modulo.split(":")[0]}
            </span>
            <span className="px-2.5 py-1 rounded-full text-xs font-bold bg-amber-600/30 text-amber-300 border border-amber-500/30">
              {currentQ.nivel}
            </span>
            <button
              onClick={() => toggleFlag(currentQ.id)}
              className={`ml-auto px-2.5 py-1 rounded-full text-xs font-bold transition-all focus:outline-none focus:ring-2 focus:ring-yellow-400 ${
                isFlagged ? "bg-yellow-500/30 text-yellow-300 border border-yellow-400/50" : "bg-white/5 text-gray-500 border border-white/10 hover:bg-white/10"
              }`}
              aria-pressed={isFlagged}
              aria-label={isFlagged ? "Quitar bandera" : "Marcar para revisar"}
            >
              {isFlagged ? "🚩 Marcada" : "🏳 Marcar"}
            </button>
          </div>

          {/* Question text */}
          <h2 className="text-xl md:text-2xl font-bold leading-relaxed text-gray-100">
            {currentQ.pregunta}
          </h2>

          {/* Options */}
          <div className="space-y-3" role="radiogroup" aria-label="Opciones de respuesta">
            {["a", "b", "c", "d"].map((key) => {
              const isSelected = userAnswer === key;
              const isCorrectOption = key === currentQ.respuesta_correcta;

              let optStyle = "bg-white/5 border-white/10 hover:bg-white/10 hover:border-white/20 text-gray-200";
              let letterStyle = "bg-white/10 text-gray-400";

              if (showFeedback) {
                if (isCorrectOption) {
                  optStyle = "bg-emerald-500/15 border-emerald-500/40 text-emerald-100";
                  letterStyle = "bg-emerald-500 text-white";
                } else if (isSelected && !isCorrectOption) {
                  optStyle = "bg-red-500/15 border-red-500/40 text-red-200";
                  letterStyle = "bg-red-500 text-white";
                } else {
                  optStyle = "bg-white/3 border-white/5 text-gray-500";
                  letterStyle = "bg-white/5 text-gray-600";
                }
              } else if (isSelected) {
                optStyle = "bg-indigo-500/20 border-indigo-500/50 text-white";
                letterStyle = "bg-indigo-500 text-white";
              }

              return (
                <button
                  key={key}
                  onClick={() => selectAnswer(currentQ.id, key)}
                  disabled={showFeedback}
                  className={`w-full text-left p-4 rounded-xl border transition-all duration-200 flex items-start gap-3 focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:cursor-default ${optStyle}`}
                  role="radio"
                  aria-checked={isSelected}
                  aria-label={`Opción ${key.toUpperCase()}: ${currentQ.opciones[key]}`}
                >
                  <span className={`w-7 h-7 shrink-0 rounded-lg flex items-center justify-center text-xs font-black transition-all ${letterStyle}`}>
                    {key.toUpperCase()}
                  </span>
                  <span className="text-sm md:text-base leading-relaxed pt-0.5">{currentQ.opciones[key]}</span>
                </button>
              );
            })}
          </div>

          {/* Feedback (practice mode) */}
          {showFeedback && (
            <div className={`rounded-xl p-4 border ${isCorrect ? "bg-emerald-500/10 border-emerald-500/30" : "bg-red-500/10 border-red-500/30"}`} role="alert">
              <p className={`font-bold mb-1 ${isCorrect ? "text-emerald-300" : "text-red-300"}`}>
                {isCorrect ? "✅ ¡Correcto!" : `❌ Incorrecto · Respuesta: ${currentQ.respuesta_correcta.toUpperCase()}`}
              </p>
              <p className="text-gray-300 text-sm leading-relaxed">{currentQ.justificacion}</p>
            </div>
          )}

          {/* Navigation */}
          <nav className="flex items-center gap-3 pt-2" aria-label="Navegación de preguntas">
            <button
              onClick={prevQuestion}
              disabled={currentIdx === 0}
              className="flex-1 py-3 rounded-xl bg-white/10 hover:bg-white/15 font-semibold text-sm transition-all focus:outline-none focus:ring-2 focus:ring-white/30 disabled:opacity-30"
            >
              ← Anterior
            </button>

            {isPractice && isAnswered && !showAnswer && (
              <button
                onClick={() => setShowAnswer(true)}
                className="px-6 py-3 rounded-xl bg-amber-500/20 border border-amber-500/40 text-amber-300 font-bold text-sm hover:bg-amber-500/30 transition-all focus:outline-none focus:ring-2 focus:ring-amber-400"
              >
                Ver respuesta
              </button>
            )}

            <button
              onClick={nextQuestion}
              disabled={currentIdx === examQuestions.length - 1}
              className="flex-1 py-3 rounded-xl bg-white/10 hover:bg-white/15 font-semibold text-sm transition-all focus:outline-none focus:ring-2 focus:ring-white/30 disabled:opacity-30"
            >
              Siguiente →
            </button>
          </nav>

          {/* Question grid navigator */}
          <details className="group">
            <summary className="text-sm text-gray-500 cursor-pointer hover:text-gray-300 transition-colors list-none flex items-center gap-2 select-none focus:outline-none">
              <svg className="w-4 h-4 transition-transform group-open:rotate-90" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
              Mapa de preguntas
            </summary>
            <div className="grid grid-cols-10 gap-1.5 mt-3" role="navigation" aria-label="Mapa de preguntas">
              {examQuestions.map((q, i) => {
                const ans = answers[q.id];
                const fl = flagged.has(q.id);
                let bg = "bg-white/10 text-gray-500";
                if (i === currentIdx) bg = "bg-indigo-500 text-white ring-2 ring-indigo-300";
                else if (ans !== undefined) bg = "bg-emerald-600/40 text-emerald-200";
                if (fl && i !== currentIdx) bg += " ring-1 ring-yellow-400";
                return (
                  <button
                    key={q.id}
                    onClick={() => goTo(i)}
                    className={`w-full aspect-square rounded-lg text-xs font-bold transition-all focus:outline-none focus:ring-2 focus:ring-white/50 ${bg}`}
                    aria-label={`Pregunta ${i + 1}${ans !== undefined ? " (respondida)" : ""}${fl ? " (marcada)" : ""}`}
                  >
                    {i + 1}
                  </button>
                );
              })}
            </div>
          </details>

          {/* Finish button for timed exams */}
          {!isPractice && (
            <div className="pt-4 border-t border-white/10">
              <div className="flex justify-between text-sm text-gray-400 mb-3">
                <span>Respondidas: <span className="text-white font-bold">{answeredCount}/{examQuestions.length}</span></span>
                <span>Marcadas: <span className="text-yellow-400 font-bold">{flagged.size}</span></span>
              </div>
              <button
                onClick={finishExam}
                className="w-full py-3 rounded-xl bg-indigo-600 hover:bg-indigo-500 font-bold transition-all focus:outline-none focus:ring-2 focus:ring-indigo-400"
              >
                Entregar examen
              </button>
            </div>
          )}
        </main>
      </div>
    );
  }

  // ── RESULTS ──
  // Review state (always declared at top level)
  const [showReview, setShowReviewState] = useState(false);
  const [reviewIdx, setReviewIdx] = useState(0);

  if (screen === "results" && results) {
    const wrongQuestions = examQuestions.filter(q => answers[q.id] !== undefined && answers[q.id] !== q.respuesta_correcta);

    if (showReview && wrongQuestions.length > 0) {
      const rq = wrongQuestions[reviewIdx];
      return (
        <div className="min-h-screen bg-gray-950 text-white p-4">
          <div className="max-w-3xl mx-auto space-y-5">
            <button onClick={() => setShowReviewState(false)} className="text-gray-400 hover:text-white text-sm flex items-center gap-1 transition-colors focus:outline-none focus:ring-2 focus:ring-white/30 rounded">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
              Volver a resultados
            </button>
            <p className="text-sm text-gray-500 font-semibold">Revisión {reviewIdx + 1} de {wrongQuestions.length}</p>
            <h2 className="text-xl font-bold text-gray-100">{rq.pregunta}</h2>
            <div className="space-y-2">
              {["a","b","c","d"].map(k => {
                const isUser = answers[rq.id] === k;
                const isRight = rq.respuesta_correcta === k;
                let style = "bg-white/5 border-white/10 text-gray-400";
                if (isRight) style = "bg-emerald-500/15 border-emerald-500/40 text-emerald-200";
                else if (isUser) style = "bg-red-500/15 border-red-500/40 text-red-200";
                return (
                  <div key={k} className={`p-3 rounded-xl border flex items-start gap-3 ${style}`}>
                    <span className="font-bold text-xs w-6 h-6 rounded flex items-center justify-center bg-white/10 shrink-0">{k.toUpperCase()}</span>
                    <span className="text-sm">{rq.opciones[k]}</span>
                    {isUser && !isRight && <span className="ml-auto text-xs text-red-400 shrink-0">Tu respuesta</span>}
                    {isRight && <span className="ml-auto text-xs text-emerald-400 shrink-0">Correcta</span>}
                  </div>
                );
              })}
            </div>
            <div className="bg-indigo-500/10 border border-indigo-500/30 rounded-xl p-4">
              <p className="text-indigo-300 text-sm">{rq.justificacion}</p>
            </div>
            <div className="flex gap-3">
              <button onClick={() => setReviewIdx(i => Math.max(0, i - 1))} disabled={reviewIdx === 0} className="flex-1 py-3 rounded-xl bg-white/10 font-semibold text-sm disabled:opacity-30 focus:outline-none focus:ring-2 focus:ring-white/30">← Anterior</button>
              <button onClick={() => setReviewIdx(i => Math.min(wrongQuestions.length - 1, i + 1))} disabled={reviewIdx === wrongQuestions.length - 1} className="flex-1 py-3 rounded-xl bg-white/10 font-semibold text-sm disabled:opacity-30 focus:outline-none focus:ring-2 focus:ring-white/30">Siguiente →</button>
            </div>
          </div>
        </div>
      );
    }

    return (
      <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center p-4">
        <div className="max-w-xl w-full space-y-6">
          {/* Score circle */}
          <div className="text-center space-y-4">
            <div className={`inline-flex items-center justify-center w-36 h-36 rounded-full border-4 ${results.passed ? "border-emerald-500 bg-emerald-500/10" : "border-red-500 bg-red-500/10"}`}>
              <div>
                <p className={`text-5xl font-black ${results.passed ? "text-emerald-400" : "text-red-400"}`}>{results.score}%</p>
                <p className="text-xs text-gray-400 mt-1">{results.correct}/{results.total}</p>
              </div>
            </div>
            <div>
              <p className={`text-2xl font-black ${results.passed ? "text-emerald-400" : "text-red-400"}`}>
                {results.passed ? "¡APROBADO!" : "NO APROBADO"}
              </p>
              <p className="text-gray-400 text-sm mt-1">Nota mínima: 65%</p>
            </div>
          </div>

          {/* Stats grid */}
          <div className="grid grid-cols-3 gap-3">
            <div className="bg-emerald-500/10 border border-emerald-500/30 rounded-xl p-3 text-center">
              <p className="text-2xl font-black text-emerald-400">{results.correct}</p>
              <p className="text-xs text-gray-400">Correctas</p>
            </div>
            <div className="bg-red-500/10 border border-red-500/30 rounded-xl p-3 text-center">
              <p className="text-2xl font-black text-red-400">{results.wrong}</p>
              <p className="text-xs text-gray-400">Incorrectas</p>
            </div>
            <div className="bg-gray-500/10 border border-gray-500/30 rounded-xl p-3 text-center">
              <p className="text-2xl font-black text-gray-400">{results.unanswered}</p>
              <p className="text-xs text-gray-400">Sin responder</p>
            </div>
          </div>

          {/* By module */}
          <div className="space-y-2">
            <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-widest">Por módulo</h3>
            {Object.entries(results.byModule).map(([mod, data]) => {
              const pct = data.total > 0 ? Math.round((data.correct / data.total) * 100) : 0;
              return (
                <div key={mod} className="flex items-center gap-3">
                  <span className="text-xs text-gray-400 w-24 shrink-0 truncate">{mod}</span>
                  <div className="flex-1 h-2 bg-white/10 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full transition-all ${pct >= 65 ? "bg-emerald-500" : "bg-red-500"}`} style={{ width: `${pct}%` }} />
                  </div>
                  <span className="text-xs font-bold w-16 text-right">{data.correct}/{data.total} ({pct}%)</span>
                </div>
              );
            })}
          </div>

          {/* By level */}
          <div className="space-y-2">
            <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-widest">Por nivel</h3>
            <div className="grid grid-cols-4 gap-2">
              {Object.entries(results.byLevel).sort().map(([lvl, data]) => {
                const pct = data.total > 0 ? Math.round((data.correct / data.total) * 100) : 0;
                return (
                  <div key={lvl} className="bg-white/5 border border-white/10 rounded-lg p-2 text-center">
                    <p className="text-xs text-gray-400">{lvl}</p>
                    <p className="font-bold">{pct}%</p>
                    <p className="text-xs text-gray-500">{data.correct}/{data.total}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Actions */}
          <div className="space-y-3 pt-2">
            {results.wrong > 0 && (
              <button
                onClick={() => { setShowReviewState(true); setReviewIdx(0); }}
                className="w-full py-3 rounded-xl bg-amber-500/20 border border-amber-500/40 text-amber-300 font-bold hover:bg-amber-500/30 transition-all focus:outline-none focus:ring-2 focus:ring-amber-400"
              >
                📝 Revisar incorrectas ({results.wrong})
              </button>
            )}
            <button
              onClick={() => { setScreen("menu"); setMode(null); }}
              className="w-full py-3 rounded-xl bg-indigo-600 hover:bg-indigo-500 font-bold transition-all focus:outline-none focus:ring-2 focus:ring-indigo-400"
            >
              Nuevo examen
            </button>
          </div>
        </div>
      </div>
    );
  }

  // Fallback
  return (
    <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center">
      <p className="text-gray-400">Cargando...</p>
    </div>
  );
}
